  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Besprechung', 'اجتماع/جلسة عمل', 'meeting', 'die', 'die Besprechungen', 'noun', 'Die Besprechung beginnt um 9 Uhr.', 'The meeting starts at 9 o''clock.', 1),
  (l_id, 'die Aufgaben', 'المهام', 'tasks', 'die', 'die Aufgaben', 'noun', 'Ich habe heute viele Aufgaben zu erledigen.', 'I have many tasks to complete today.', 2),
  (l_id, 'die Frist', 'الموعد النهائي', 'deadline', 'die', 'die Fristen', 'noun', 'Die Frist für das Projekt endet am Freitag.', 'The deadline for the project ends on Friday.', 3),
  (l_id, 'die Vereinbarung', 'اتفاقية', 'agreement', 'die', 'die Vereinbarungen', 'noun', 'Wir haben eine Vereinbarung getroffen.', 'We have reached an agreement.', 4),
  (l_id, 'der Vorgesetzte', 'المشرف/المدير', 'supervisor', 'der', 'die Vorgesetzten', 'noun', 'Mein Vorgesetzter hat mir neue Aufgaben gegeben.', 'My supervisor gave me new tasks.', 5),
  (l_id, 'die Abteilung', 'القسم', 'department', 'die', 'die Abteilungen', 'noun', 'In unserer Abteilung arbeiten zehn Personen.', 'Ten people work in our department.', 6);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Passiv mit Modalverben', 'Im B2-Niveau kombinieren wir das Passiv mit Modalverben, um auszudrücken, was getan werden muss, kann, darf oder soll. Die Struktur ist: Modalverb + Partizip Perfekt + werden. Der Handelnde (Agent) wird oft mit "von" eingeleitet.', '[{"rule":"Passiv mit Modalverb: Modalverb (konjugiert) + Partizip Perfekt + werden","note":"Das Projekt muss abgeschlossen werden."},{"rule":"muss + Partizip + werden drückt eine Notwendigkeit aus.","note":"Der Bericht muss bis Montag geschrieben werden."},{"rule":"kann + Partizip + werden drückt eine Möglichkeit aus.","note":"Die Lieferung kann am Freitag erfolgen."},{"rule":"soll + Partizip + werden drückt eine Empfehlung oder Anweisung aus.","note":"Die Rechnung soll sofort bezahlt werden."},{"rule":"darf + Partizip + werden drückt eine Erlaubnis aus.","note":"Hier darf nicht geraucht werden."}]', '[{"german":"Der Bericht muss bis Montag geschrieben werden.","arabic":"يجب كتابة التقرير بحلول يوم الاثنين.","english":"The report must be written by Monday."},{"german":"Die Lieferung kann per Express erfolgen.","arabic":"يمكن أن يتم التسليم عن طريق البريد السريع.","english":"The delivery can be made by express."},{"german":"Die Rechnung soll sofort bezahlt werden.","arabic":"يجب دفع الفاتورة فوراً.","english":"The invoice should be paid immediately."},{"german":"Im Besprechungsraum darf nicht telefoniert werden.","arabic":"لا يُسمح بالاتصال الهاتفي في غرفة الاجتماعات.","english":"Phoning is not allowed in the meeting room."},{"german":"Der Vertrag ist bis Freitag zu unterschreiben.","arabic":"يجب توقيع العقد بحلول يوم الجمعة.","english":"The contract is to be signed by Friday."}]', '[{"mistake":"Der Bericht muss geschrieben.","correction":"Der Bericht muss geschrieben werden.","explanation":"Im Passiv mit Modalverben muss \"werden\" am Ende stehen."},{"mistake":"Die Lieferung kann geliefert werden von der Firma.","correction":"Die Lieferung kann von der Firma geliefert werden.","explanation":"\"Von\" steht vor dem Handelnden, nicht am Satzende."},{"mistake":"Die Aufgaben müssen gemacht.","correction":"Die Aufgaben müssen gemacht werden.","explanation":"Passiv mit Modalverb braucht immer \"werden\" im Infinitiv."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Der Bericht _____ bis Montag geschrieben _____. (muss / müssen)', '["muss ... werden","müssen ... werden","muss ... sein","müssen ... sein"]', 'muss ... werden', '"Der Bericht" ist Singular, also "muss ... werden".', 1, 1),
  (l_id, 'multiple_choice', 'Was ist die korrekte Passivform? "Man kann das Problem lösen."', '["Das Problem kann gelöst werden.","Das Problem wird lösen können.","Das Problem kann lösen.","Das Problem wird gelöst können."]', 'Das Problem kann gelöst werden.', 'Passiv mit können: kann + Partizip + werden.', 1, 2),
  (l_id, 'translation', 'Übersetze: "The invoice must be paid immediately."', '["Die Rechnung muss sofort bezahlt werden.","Die Rechnung kann sofort bezahlt werden.","Die Rechnung soll sofort bezahlt werden.","Die Rechnung darf sofort bezahlt werden."]', 'Die Rechnung muss sofort bezahlt werden.', '"Muss" drückt eine Notwendigkeit aus.', 1, 3),
  (l_id, 'fill_gap', 'Hier _____ nicht geraucht _____. (dürfen - Passiv)', '["darf ... werden","dürfen ... werden","darf ... sein","dürfen ... sein"]', 'darf ... werden', 'Es heißt "darf" (Singular, unpersönlich) + "werden".', 1, 4),
  (l_id, 'multiple_choice', 'Was bedeutet "Der Antrag ist bis Freitag einzureichen."?', '["Der Antrag kann bis Freitag eingereicht werden.","Der Antrag muss bis Freitag eingereicht werden.","Der Antrag darf bis Freitag eingereicht werden.","Der Antrag soll bis Freitag eingereicht werden."]', 'Der Antrag muss bis Freitag eingereicht werden.', '"ist ... einzureichen" = muss eingereicht werden (Notwendigkeit).', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Besprechung"?', '["الاجتماع","المهمة","الموعد النهائي","القسم"]', 'الاجتماع', 1, 1),
  (l_id, 'fill_blank', 'Die Aufgaben _____ erledigt werden. (müssen)', '["muss","müssen","kann","darf"]', 'müssen', 1, 2),
  (l_id, 'true_false', 'Im Passiv mit Modalverb steht "werden" am Satzende.', '["Richtig","Falsch"]', 'Richtig', 1, 3),
  (l_id, 'multiple_choice', '"Der Vertrag kann unterschrieben werden" bedeutet:', '["يجب توقيع العقد","يمكن توقيع العقد","يُسمح بتوقيع العقد","تم توقيع العقد"]', 'يمكن توقيع العقد', 1, 4),
  (l_id, 'multiple_choice', 'Was ist "die Frist"?', '["الموعد النهائي","الراتب","الإجازة","المهمة"]', 'الموعد النهائي', 1, 5),
  (l_id, 'fill_blank', 'Der Bericht _____ bis Freitag geschrieben werden. (Modalverb für Notwendigkeit)', '["kann","muss","darf","soll"]', 'muss', 1, 6);
