  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Anfrage', 'استفسار/طلب معلومات', 'inquiry', 'die', 'die Anfragen', 'noun', 'Wir haben eine Anfrage von einem Kunden erhalten.', 'We have received an inquiry from a customer.', 1),
  (l_id, 'das Angebot', 'عرض', 'offer', 'das', 'die Angebote', 'noun', 'Vielen Dank für Ihr Angebot.', 'Thank you very much for your offer.', 2),
  (l_id, 'die Bestätigung', 'تأكيد', 'confirmation', 'die', 'die Bestätigungen', 'noun', 'Wir warten noch auf die Bestätigung.', 'We are still waiting for the confirmation.', 3),
  (l_id, 'die Reklamation', 'شكوى', 'complaint', 'die', 'die Reklamationen', 'noun', 'Der Kunde hat eine Reklamation eingereicht.', 'The customer has filed a complaint.', 4),
  (l_id, 'die Zahlung', 'الدفع', 'payment', 'die', 'die Zahlungen', 'noun', 'Die Zahlung ist fällig am 15. Mai.', 'The payment is due on May 15th.', 5),
  (l_id, 'der Betreff', 'الموضوع', 'subject line', 'der', 'die Betreffe', 'noun', 'Bitte geben Sie einen klaren Betreff an.', 'Please provide a clear subject line.', 6),
  (l_id, 'der Anhang', 'المرفق', 'attachment', 'der', 'die Anhänge', 'noun', 'Im Anhang finden Sie die Unterlagen.', 'Please find the documents attached.', 7);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Kausalsätze mit wegen, aufgrund, dank', 'Im B2-Niveau drücken wir Gründe nicht nur mit "weil" und "da" aus, sondern auch mit präpositionalen Ausdrücken wie "wegen" (Grund, oft negativ), "aufgrund" (formell, neutral) und "dank" (positiver Grund). Diese Präpositionen regieren den Genitiv, im gesprochenen Deutsch häufig den Dativ.', '[{"rule":"\"wegen\" + Genitiv: Grund, oft negativ oder neutral.","note":"Wegen des Streiks bleibt die Firma geschlossen."},{"rule":"\"aufgrund\" + Genitiv: formeller Grund, neutral.","note":"Aufgrund der hohen Nachfrage liefern wir später."},{"rule":"\"dank\" + Genitiv (oder Dativ): positiver Grund.","note":"Dank der guten Zusammenarbeit wurde das Projekt erfolgreich."},{"rule":"Im gesprochenen Deutsch wird oft der Dativ verwendet.","note":"Wegen dem Fehler, aufgrund dem Bericht (umgangssprachlich)."}]', '[{"german":"Wegen des schlechten Wetters fällt die Veranstaltung aus.","arabic":"بسبب سوء الطقس، تم إلغاء الفعالية.","english":"Due to the bad weather, the event is canceled."},{"german":"Aufgrund der hohen Nachfrage haben wir die Produktion erhöht.","arabic":"بسبب الطلب المرتفع، قمنا بزيادة الإنتاج.","english":"Due to high demand, we have increased production."},{"german":"Dank der guten Vorbereitung war die Präsentation ein Erfolg.","arabic":"بفضل التحضير الجيد، كان العرض التقديمي ناجحاً.","english":"Thanks to the good preparation, the presentation was a success."},{"german":"Wegen des Fehlers musste der Bericht korrigiert werden.","arabic":"بسبب الخطأ، كان لا بد من تصحيح التقرير.","english":"Because of the error, the report had to be corrected."},{"german":"Aufgrund der aktuellen Lage arbeiten wir im Homeoffice.","arabic":"بسبب الوضع الحالي، نحن نعمل من المنزل.","english":"Due to the current situation, we are working from home."}]', '[{"mistake":"Wegen der Regen bleibt die Veranstaltung aus.","correction":"Wegen des Regens bleibt die Veranstaltung aus.","explanation":"\"Regen\" ist maskulin (der Regen), Genitiv: des Regens."},{"mistake":"Dank des Fehlers haben wir etwas gelernt.","correction":"Besser: \"Wegen des Fehlers...\"","explanation":"\"Dank\" wird normalerweise für positive Gründe verwendet."},{"mistake":"Aufgrund der schlechten Ergebnisse, wir müssen etwas ändern.","correction":"Aufgrund der schlechten Ergebnisse müssen wir etwas ändern.","explanation":"Nach der Präpositionalphrase folgt das konjugierte Verb direkt (kein Komma + Subjekt)."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', '_____ des Lärms konnte ich mich nicht konzentrieren. (wegen / dank)', '["Wegen","Dank","Aufgrund von","Trotz"]', 'Wegen', '"Wegen" wird für negative Gründe verwendet.', 1, 1),
  (l_id, 'translation', 'Übersetze: "Thanks to your help, we finished on time."', '["Wegen Ihrer Hilfe wurden wir rechtzeitig fertig.","Dank Ihrer Hilfe wurden wir rechtzeitig fertig.","Aufgrund Ihrer Hilfe wurden wir rechtzeitig fertig.","Trotz Ihrer Hilfe wurden wir rechtzeitig fertig."]', 'Dank Ihrer Hilfe wurden wir rechtzeitig fertig.', '"Dank" drückt einen positiven Grund aus.', 1, 2),
  (l_id, 'multiple_choice', 'Welcher Satz ist korrekt formuliert?', '["Wegen der Verspätung wir müssen warten.","Wegen der Verspätung müssen wir warten.","Wegen der Verspätung, wir müssen warten.","Wegen der Verspätung, müssen wir warten."]', 'Wegen der Verspätung müssen wir warten.', 'Nach der Präpositionalphrase folgt das Verb direkt.', 1, 3),
  (l_id, 'fill_gap', '_____ der guten Zusammenarbeit war das Projekt erfolgreich. (Dank / Wegen)', '["Dank","Wegen","Aufgrund","Trotz"]', 'Dank', 'Positive Ursache -> "dank".', 1, 4),
  (l_id, 'multiple_choice', 'Was ist der Genitiv von "der Kunde"?', '["des Kunden","des Kundes","der Kunde","den Kunden"]', 'des Kunden', 'Der Kunde -> Genitiv: des Kunden (n-Deklination).', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Anfrage"?', '["العرض","الاستفسار","التأكيد","الشكوى"]', 'الاستفسار', 1, 1),
  (l_id, 'true_false', '"Dank" wird für positive Gründe verwendet.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', '_____ des Streiks bleibt die Firma geschlossen. (wegen)', '["Wegen","Dank","Aufgrund","Trotz"]', 'Wegen', 1, 3),
  (l_id, 'multiple_choice', '"Der Anhang" in einer E-Mail ist:', '["الموضوع","المرفق","التحية","التوقيع"]', 'المرفق', 1, 4),
  (l_id, 'true_false', '"Aufgrund" ist informeller als "wegen".', '["Richtig","Falsch"]', 'Falsch', 1, 5),
  (l_id, 'multiple_choice', 'Welche Präposition regiert den Genitiv?', '["trotz","durch","für","ohne"]', 'trotz', 1, 6);
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'trotzdem', 'مع ذلك/رغم ذلك', 'nevertheless', NULL, NULL, 'adverb', 'Es hat geregnet, trotzdem war die Veranstaltung ein Erfolg.', 'It rained, nevertheless the event was a success.', 1),
  (l_id, 'dennoch', 'رغم ذلك/مع ذلك', 'yet/nevertheless', NULL, NULL, 'adverb', 'Die Aufgaben waren schwer, dennoch haben wir sie erledigt.', 'The tasks were difficult, yet we completed them.', 2),
  (l_id, 'allerdings', 'ولكن/مع ذلك', 'however/though', NULL, NULL, 'adverb', 'Das Angebot ist gut, allerdings müssen wir die Konditionen prüfen.', 'The offer is good, however we need to check the terms.', 3),
  (l_id, 'zwar ... aber', 'بالرغم من ... إلا أن', 'admittedly ... but', NULL, NULL, 'conjunction', 'Der Vorschlag ist zwar interessant, aber nicht umsetzbar.', 'The proposal is admittedly interesting, but not feasible.', 4),
  (l_id, 'zudem', 'بالإضافة إلى ذلك', 'in addition/furthermore', NULL, NULL, 'adverb', 'Das Projekt ist zeitaufwendig, zudem ist es teuer.', 'The project is time-consuming, furthermore it is expensive.', 5);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Konnektoren: trotzdem, dennoch, allerdings', 'Diese Konnektoren verbinden Sätze und drücken einen Gegensatz oder eine Einschränkung aus. "Trotzdem" und "dennoch" sind Synonyme und bedeuten "despite that". "Allerdings" ist milder und leitet eine Einschränkung oder einen Einwand ein. Sie sind satzverbindende Adverbien (Position 1 oder 3).', '[{"rule":"\"trotzdem\" = trotz + dem. Drückt einen Gegensatz aus.","note":"Satz 1. Trotzdem + Verb + Subjekt..."},{"rule":"\"dennoch\" ist formeller als \"trotzdem\", gleiche Bedeutung.","note":"Die Lage ist schwierig, dennoch sind wir optimistisch."},{"rule":"\"allerdings\" leitet eine Einschränkung ein, milder als trotzdem.","note":"Ich stimme zu, allerdings habe ich Bedenken."},{"rule":"Als Konnektoren mit Nullposition stehen sie im Satz nach dem Verb.","note":"Sie haben sich sehr bemüht, der Erfolg blieb allerdings aus."},{"rule":"\"zwar ... aber\" verbindet zwei gegensätzliche Aussagen.","note":"Die Idee ist zwar gut, aber zu teuer."}]', '[{"german":"Es gab technische Probleme, trotzdem verlief die Präsentation gut.","arabic":"كانت هناك مشاكل تقنية، ومع ذلك سار العرض التقديمي بشكل جيد.","english":"There were technical problems, nevertheless the presentation went well."},{"german":"Die Verhandlungen waren schwierig, dennoch konnten wir eine Einigung erzielen.","arabic":"كانت المفاوضات صعبة، ومع ذلك تمكنا من التوصل إلى اتفاق.","english":"The negotiations were difficult, yet we were able to reach an agreement."},{"german":"Der Vorschlag ist interessant, allerdings müssen wir das Budget prüfen.","arabic":"الاقتراح مثير للاهتمام، ولكن يجب علينا مراجعة الميزانية.","english":"The proposal is interesting, however we need to check the budget."},{"german":"Die Methode ist zwar effektiv, aber sehr zeitaufwendig.","arabic":"الطريقة فعالة بالرغم من ذلك، ولكنها تستغرق وقتاً طويلاً.","english":"The method is admittedly effective, but very time-consuming."},{"german":"Die Firma wächst, zudem expandieren wir ins Ausland.","arabic":"الشركة تنمو، بالإضافة إلى ذلك نحن نتوسع في الخارج.","english":"The company is growing, in addition we are expanding abroad."}]', '[{"mistake":"Es hat geregnet, trotzdem die Veranstaltung war ein Erfolg.","correction":"Es hat geregnet, trotzdem war die Veranstaltung ein Erfolg.","explanation":"Nach \"trotzdem\" kommt das Verb an Position 2, nicht das Subjekt."},{"mistake":"Allerdings, ich habe keine Zeit.","correction":"Allerdings habe ich keine Zeit. oder Ich habe allerdings keine Zeit.","explanation":"\"Allerdings\" steht an Position 1 oder mitten im Satz, nie allein mit Komma."},{"mistake":"Die Arbeit ist zwar schwer, dennoch macht sie Spaß.","correction":"Die Arbeit ist zwar schwer, aber sie macht Spaß.","explanation":"\"Zwar\" korrespondiert mit \"aber\", nicht mit \"dennoch\"."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Die Arbeit war anstrengend, _____ hat sie Spaß gemacht. (trotzdem)', '["trotzdem","weil","denn","obwohl"]', 'trotzdem', 'Gegensatz zwischen anstrengend und Spaß -> trotzdem.', 1, 1),
  (l_id, 'multiple_choice', 'Welcher Konnektor ist formeller als "trotzdem"?', '["denn","dennoch","weil","deshalb"]', 'dennoch', '"Dennoch" ist die formellere Variante von "trotzdem".', 1, 2),
  (l_id, 'translation', 'Übersetze: "The proposal is interesting, however too expensive."', '["Der Vorschlag ist interessant, trotzdem zu teuer.","Der Vorschlag ist interessant, allerdings zu teuer.","Der Vorschlag ist interessant, deswegen zu teuer.","Der Vorschlag ist interessant, obwohl zu teuer."]', 'Der Vorschlag ist interessant, allerdings zu teuer.', '"Allerdings" drückt eine Einschränkung aus.', 1, 3),
  (l_id, 'fill_gap', 'Die Idee ist _____ gut, _____ nicht umsetzbar. (zwar ... aber)', '["zwar ... aber","entweder ... oder","nicht nur ... sondern auch","weder ... noch"]', 'zwar ... aber', 'Gegensatz: zwar (zugeben) + aber (Einschränkung).', 1, 4),
  (l_id, 'multiple_choice', 'Welcher Satz ist korrekt?', '["Trotzdem, wir haben es geschafft.","Trotzdem haben wir es geschafft.","Trotzdem wir haben es geschafft.","Trotzdem, haben wir es geschafft."]', 'Trotzdem haben wir es geschafft.', '"Trotzdem" + Verb (Position 2) + Subjekt.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "trotzdem"?', '["لذلك","مع ذلك","بسبب","بالرغم من أن"]', 'مع ذلك', 1, 1),
  (l_id, 'true_false', '"Dennoch" ist formeller als "trotzdem".', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Der Vorschlag ist interessant, _____ müssen wir das Budget prüfen. (allerdings)', '["allerdings","trotzdem","dennoch","obwohl"]', 'allerdings', 1, 3),
  (l_id, 'multiple_choice', 'Welche Konjunktion passt zu "zwar"?', '["aber","denn","und","oder"]', 'aber', 1, 4),
  (l_id, 'true_false', 'Nach "trotzdem" steht das Subjekt an Position 2.', '["Richtig","Falsch"]', 'Falsch', 1, 5),
  (l_id, 'multiple_choice', 'Was ist die Funktion von "allerdings"?', '["Grund angeben","Einschränkung","Zeitfolge","Alternative"]', 'Einschränkung', 1, 6);
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Tagesordnung', 'جدول الأعمال', 'agenda', 'die', 'die Tagesordnungen', 'noun', 'Die Tagesordnung für das Meeting umfasst fünf Punkte.', 'The agenda for the meeting includes five items.', 1),
  (l_id, 'der Verhandlungspartner', 'شريك المفاوضات', 'negotiating partner', 'der', 'die Verhandlungspartner', 'noun', 'Wir haben uns mit den Verhandlungspartnern getroffen.', 'We met with the negotiating partners.', 2),
  (l_id, 'das Protokoll', 'محضر الاجتماع', 'minutes', 'das', 'die Protokolle', 'noun', 'Wer schreibt heute das Protokoll?', 'Who is taking the minutes today?', 3),
  (l_id, 'die Einigung', 'اتفاق/تفاهم', 'agreement', 'die', 'die Einigungen', 'noun', 'Nach langen Gesprächen wurde eine Einigung erzielt.', 'After long talks an agreement was reached.', 4),
  (l_id, 'der Kompromiss', 'حل وسط', 'compromise', 'der', 'die Kompromisse', 'noun', 'Wir müssen einen Kompromiss finden.', 'We need to find a compromise.', 5),
  (l_id, 'die Zustimmung', 'الموافقة', 'approval', 'die', 'die Zustimmungen', 'noun', 'Der Vorschlag fand große Zustimmung.', 'The proposal received wide approval.', 6);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Konnektoren in Diskussionen: trotzdem, dennoch, allerdings', 'In Besprechungen und Verhandlungen verwenden wir Konnektoren, um höflich zu widersprechen, Einschränkungen zu machen oder Gegensätze auszudrücken. "Allerdings" ist besonders nützlich für diplomatische Einschränkungen.', '[{"rule":"\"Allerdings\" am Satzanfang leitet einen Einwand ein.","note":"Allerdings müssen wir die Kosten berücksichtigen."},{"rule":"\"Trotzdem\" betont, dass etwas trotz eines Hindernisses passiert.","note":"Die Bedingungen sind hart, trotzdem stimmen wir zu."},{"rule":"\"Dennoch\" in formellen Verhandlungen verwenden.","note":"Die Einigung ist möglich, dennoch gibt es offene Punkte."},{"rule":"Konnektoren können auch mitten im Satz stehen.","note":"Wir stimmen dem Vorschlag allerdings nicht zu."}]', '[{"german":"Ihr Vorschlag ist interessant, allerdings haben wir Bedenken bezüglich des Budgets.","arabic":"اقتراحكم مثير للاهتمام، ولكن لدينا تحفظات بخصوص الميزانية.","english":"Your proposal is interesting, however we have concerns regarding the budget."},{"german":"Die Frist ist kurz, trotzdem werden wir das Projekt abschließen.","arabic":"الموعد النهائي قصير، ومع ذلك سنكمل المشروع.","english":"The deadline is short, nevertheless we will complete the project."},{"german":"Die Verhandlungen waren schwierig, dennoch wurde eine Einigung erzielt.","arabic":"كانت المفاوضات صعبة، ومع ذلك تم التوصل إلى اتفاق.","english":"The negotiations were difficult, yet an agreement was reached."},{"german":"Wir stimmen zu, allerdings unter bestimmten Bedingungen.","arabic":"نوافق، ولكن بشروط معينة.","english":"We agree, however under certain conditions."}]', '[{"mistake":"Allerdings, wir haben Bedenken.","correction":"Allerdings haben wir Bedenken.","explanation":"Kein Komma nach \"allerdings\" am Satzanfang."},{"mistake":"Zwar der Preis ist hoch, aber die Qualität stimmt.","correction":"Der Preis ist zwar hoch, aber die Qualität stimmt.","explanation":"\"Zwar\" steht nach dem ersten Satzteil, nicht am Anfang."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Ihr Angebot ist interessant, _____ haben wir Bedenken. (allerdings)', '["allerdings","trotzdem","dennoch","deshalb"]', 'allerdings', '"Allerdings" leitet einen höflichen Einwand ein.', 1, 1),
  (l_id, 'multiple_choice', 'Welcher Satz eignet sich am besten für eine diplomatische Ablehnung?', '["Das ist falsch!","Allerdings sehe ich das anders.","Nein, das stimmt nicht.","Sie irren sich."]', 'Allerdings sehe ich das anders.', 'Höflicher Widerspruch mit "allerdings".', 1, 2),
  (l_id, 'translation', 'Übersetze: "The deadline is tight, nevertheless we will make it."', '["Die Frist ist knapp, trotzdem schaffen wir es.","Die Frist ist knapp, allerdings schaffen wir es.","Die Frist ist knapp, deswegen schaffen wir es.","Die Frist ist knapp, obwohl wir es schaffen."]', 'Die Frist ist knapp, trotzdem schaffen wir es.', '"Trotzdem" drückt den Gegensatz zur knappen Frist aus.', 1, 3),
  (l_id, 'fill_gap', 'Der Preis ist _____ hoch, _____ die Qualität ist ausgezeichnet. (zwar ... aber)', '["zwar ... aber","nicht nur ... sondern auch","weder ... noch","entweder ... oder"]', 'zwar ... aber', 'Gegensatz zwischen Preis und Qualität.', 1, 4),
  (l_id, 'multiple_choice', 'Was bedeutet "das Protokoll" im Meeting-Kontext?', '["البروتوكول الدبلوماسي","محضر الاجتماع","الجدول الزمني","التقرير السنوي"]', 'محضر الاجتماع', 'Das Protokoll ist die schriftliche Aufzeichnung eines Meetings.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Tagesordnung"?', '["جدول الأعمال","محضر الاجتماع","الموعد النهائي","جدول المواعيد"]', 'جدول الأعمال', 1, 1),
  (l_id, 'true_false', '"Allerdings" leitet einen Einwand ein.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Die Verhandlungen waren hart, _____ wurde eine Einigung erzielt. (dennoch)', '["dennoch","deshalb","weil","denn"]', 'dennoch', 1, 3),
  (l_id, 'multiple_choice', 'Was ist ein "Kompromiss"?', '["اتفاق","حل وسط","رفض","اقتراح"]', 'حل وسط', 1, 4),
  (l_id, 'true_false', '"Trotzdem" und "dennoch" haben die gleiche Bedeutung.', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'multiple_choice', 'Welcher Satz ist ein höflicher Widerspruch?', '["Das stimmt nicht.","Allerdings bin ich anderer Meinung.","Nein.","Falsch!"]', 'Allerdings bin ich anderer Meinung.', 1, 6);
