  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Kündigung', 'الإنهاء/الاستقالة', 'termination/resignation', 'die', 'die Kündigungen', 'noun', 'Die Kündigung muss schriftlich erfolgen.', 'The resignation must be in writing.', 1),
  (l_id, 'das Vorstellungsgespräch', 'مقابلة عمل', 'job interview', 'das', 'die Vorstellungsgespräche', 'noun', 'Morgen habe ich ein Vorstellungsgespräch.', 'Tomorrow I have a job interview.', 2),
  (l_id, 'die Gehaltsverhandlung', 'تفاوض على الراتب', 'salary negotiation', 'die', 'die Gehaltsverhandlungen', 'noun', 'Die Gehaltsverhandlung war erfolgreich.', 'The salary negotiation was successful.', 3),
  (l_id, 'die Stellenanzeige', 'إعلان وظيفة', 'job advertisement', 'die', 'die Stellenanzeigen', 'noun', 'Ich habe mich auf eine Stellenanzeige beworben.', 'I applied for a job advertisement.', 4),
  (l_id, 'das Arbeitszeugnis', 'شهادة عمل', 'employment reference', 'das', 'die Arbeitszeugnisse', 'noun', 'Das Arbeitszeugnis fällt sehr gut aus.', 'The employment reference is very good.', 5);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Wiederholung: Passiv mit Modalverben, Kausalsätze und Konnektoren', 'In dieser Wiederholungslektion festigen wir die drei Hauptgrammatikthemen: Passiv mit Modalverben (Notwendigkeit/Möglichkeit ausdrücken), Kausalsätze mit wegen/aufgrund/dank (Gründe angeben) und Konnektoren wie trotzdem/dennoch/allerdings (Gegensätze und Einschränkungen).', '[{"rule":"Passiv mit Modalverb: Modalverb + Partizip Perfekt + werden","note":"Der Bericht muss geschrieben werden."},{"rule":"Kausale Präpositionen + Genitiv: wegen (negativ), aufgrund (neutral), dank (positiv).","note":"Wegen des Fehlers, aufgrund der Nachfrage, dank der Hilfe."},{"rule":"Konnektoren trotzdem/dennoch: Gegensatz, Verb an Position 2.","note":"Es war schwer, trotzdem haben wir es geschafft."},{"rule":"Allerdings: milde Einschränkung, oft in Diskussionen.","note":"Ich stimme zu, allerdings unter Bedingungen."}]', '[{"german":"Die Aufgaben müssen bis Freitag erledigt werden.","arabic":"يجب إكمال المهام بحلول يوم الجمعة.","english":"The tasks must be completed by Friday."},{"german":"Wegen des Fehlers musste der Bericht korrigiert werden.","arabic":"بسبب الخطأ، كان لا بد من تصحيح التقرير.","english":"Because of the error, the report had to be corrected."},{"german":"Dank der guten Vorbereitung verlief die Präsentation reibungslos.","arabic":"بفضل التحضير الجيد، سار العرض التقديمي بسلاسة.","english":"Thanks to good preparation, the presentation went smoothly."},{"german":"Die Verhandlungen waren schwierig, dennoch gab es eine Einigung.","arabic":"كانت المفاوضات صعبة، ومع ذلك تم التوصل إلى اتفاق.","english":"The negotiations were difficult, yet there was an agreement."}]', '[{"mistake":"Der Vertrag muss unterschrieben.","correction":"Der Vertrag muss unterschrieben werden.","explanation":"Passiv mit Modalverb: \"werden\" am Ende nicht vergessen."},{"mistake":"Wegen dem Fehler haben wir den Termin verpasst.","correction":"Formell korrekt: Wegen des Fehlers haben wir den Termin verpasst.","explanation":"Formell korrekt ist der Genitiv: \"des Fehlers\"."},{"mistake":"Die Qualität ist gut, trotzdem der Preis ist hoch.","correction":"Die Qualität ist gut, trotzdem ist der Preis hoch.","explanation":"Nach \"trotzdem\" folgt das Verb, dann das Subjekt."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Die E-Mails _____ bis 15 Uhr beantwortet _____. (müssen - Passiv)', '["müssen ... werden","muss ... werden","müssen ... sein","muss ... sein"]', 'müssen ... werden', '"Die E-Mails" ist Plural -> "müssen ... werden".', 1, 1),
  (l_id, 'multiple_choice', 'Welcher Satz enthält einen Kausalsatz?', '["Trotzdem hat sie angerufen.","Wegen der Verspätung kamen wir zu spät.","Allerdings müssen wir warten.","Der Bericht muss geschrieben werden."]', 'Wegen der Verspätung kamen wir zu spät.', '"Wegen" drückt einen Grund (Kausalität) aus.', 1, 2),
  (l_id, 'translation', 'Übersetze: "Thanks to your support we succeeded."', '["Wegen Ihrer Unterstützung hatten wir Erfolg.","Dank Ihrer Unterstützung hatten wir Erfolg.","Aufgrund Ihrer Unterstützung hatten wir Erfolg.","Trotz Ihrer Unterstützung hatten wir Erfolg."]', 'Dank Ihrer Unterstützung hatten wir Erfolg.', '"Dank" wird für positive Ursachen verwendet.', 1, 3),
  (l_id, 'fill_gap', 'Das Projekt ist _____ interessant, _____ schwer umsetzbar. (zwar ... aber)', '["zwar ... aber","sowohl ... als auch","weder ... noch","nicht nur ... sondern auch"]', 'zwar ... aber', 'Gegensatz: interessant vs. schwer umsetzbar.', 1, 4),
  (l_id, 'multiple_choice', 'Welcher Konnektor passt? "Die Arbeit war hart, _____ hat sie Spaß gemacht."', '["trotzdem","weil","denn","deshalb"]', 'trotzdem', 'Gegensatz zwischen hart und Spaß -> trotzdem.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Kündigung"?', '["الإنهاء","التوظيف","الراتب","الإجازة"]', 'الإنهاء', 1, 1),
  (l_id, 'true_false', '"Dank" drückt einen positiven Grund aus.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Die Rechnung _____ sofort bezahlt werden. (soll)', '["soll","sollt","sollen","sollst"]', 'soll', 1, 3),
  (l_id, 'multiple_choice', 'Wie bildet man das Passiv mit Modalverb?', '["Modalverb + Partizip + werden","Modalverb + Infinitiv","Modalverb + zu + Infinitiv","Modalverb + Partizip"]', 'Modalverb + Partizip + werden', 1, 4),
  (l_id, 'true_false', '"Allerdings" ist stärker als "trotzdem".', '["Richtig","Falsch"]', 'Falsch', 1, 5),
  (l_id, 'multiple_choice', 'Welche Präposition bedeutet "بفضل" (positiver Grund)?', '["wegen","dank","trotz","aufgrund"]', 'dank', 1, 6);
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'multiple_choice', 'Was ist der Infinitiv im Passiv mit Modalverb? "Die Aufgaben müssen erledigt _____."', '["werden","sein","worden","werden sein"]', 'werden', 'Passiv mit Modalverb: Modalverb + Partizip + werden.', 1, 1),
  (l_id, 'fill_gap', '_____ der hohen Nachfrage haben wir die Produktion erhöht. (aufgrund)', '["Aufgrund","Wegen","Dank","Trotz"]', 'Aufgrund', '"Aufgrund" ist formell und neutral.', 1, 2),
  (l_id, 'translation', 'Übersetze: "The meeting was difficult, nevertheless productive."', '["Das Meeting war schwierig, trotzdem produktiv.","Das Meeting war schwierig, deswegen produktiv.","Das Meeting war schwierig, obwohl produktiv.","Das Meeting war schwierig, weil produktiv."]', 'Das Meeting war schwierig, trotzdem produktiv.', 'Gegensatz: schwierig vs. produktiv.', 1, 3),
  (l_id, 'multiple_choice', 'Was bedeutet "dank" im Vergleich zu "wegen"?', '["Dank ist negativ, wegen ist positiv.","Dank ist positiv, wegen ist neutral/negativ.","Dank und wegen sind Synonyme.","Dank ist formeller als wegen."]', 'Dank ist positiv, wegen ist neutral/negativ.', '"Dank" drückt einen positiven Grund aus, "wegen" ist neutral oder negativ.', 1, 4),
  (l_id, 'fill_gap', 'Der Vorschlag ist _____ interessant, _____ nicht praktikabel. (zwar ... aber)', '["zwar ... aber","entweder ... oder","weder ... noch","sowohl ... als auch"]', 'zwar ... aber', 'Gegensatz mit "zwar ... aber".', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was ist "die Besprechung"?', '["الاجتماع","المراجعة","المناقشة","المقابلة"]', 'الاجتماع', 1, 1),
  (l_id, 'true_false', '"Dennoch" und "trotzdem" sind Synonyme.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Die Rechnung _____ sofort bezahlt werden. (muss)', '["muss","müssen","kann","darf"]', 'muss', 1, 3),
  (l_id, 'multiple_choice', 'Welche Präposition verlangt den Genitiv?', '["wegen","durch","für","ohne"]', 'wegen', 1, 4),
  (l_id, 'true_false', 'Im Satz "Trotzdem haben wir es geschafft" steht das Verb an Position 2.', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'multiple_choice', 'Was ist das Gegenteil von "zustimmen"?', '["ablehnen","fragen","diskutieren","verhandeln"]', 'ablehnen', 1, 6),
  (l_id, 'fill_blank', 'Der Vertrag _____ bis Freitag unterschrieben werden. (kann)', '["kann","könnt","können","kannst"]', 'kann', 1, 7),
  (l_id, 'multiple_choice', 'Was bedeutet "die Gehaltsverhandlung"?', '["مقابلة العمل","تفاوض الراتب","تقييم الأداء","التدريب الوظيفي"]', 'تفاوض الراتب', 1, 8);
  insert into public.course_modules (level_id, title, description, objectives, order_index, estimated_hours, is_published)
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die These', 'الأطروحة/الفرضية', 'thesis', 'die', 'die Thesen', 'noun', 'Der Redner stellte eine interessante These auf.', 'The speaker put forward an interesting thesis.', 1),
  (l_id, 'das Argument', 'الحجة', 'argument', 'das', 'die Argumente', 'noun', 'Seine Argumente waren überzeugend.', 'His arguments were convincing.', 2),
  (l_id, 'die Gegenargumentation', 'الحجة المضادة/الرد', 'counterargument', 'die', 'die Gegenargumentationen', 'noun', 'Eine gute Gegenargumentation ist wichtig für eine Debatte.', 'A good counterargument is important for a debate.', 3),
  (l_id, 'der Standpunkt', 'وجهة النظر', 'point of view', 'der', 'die Standpunkte', 'noun', 'Ich verstehe Ihren Standpunkt, sehe es aber anders.', 'I understand your point of view, but I see it differently.', 4),
  (l_id, 'die Überzeugung', 'الاقتناع', 'conviction', 'die', 'die Überzeugungen', 'noun', 'Aus tiefer Überzeugung lehne ich Gewalt ab.', 'Out of deep conviction I reject violence.', 5),
  (l_id, 'strittig', 'مثير للجدل', 'controversial', NULL, NULL, 'adjective', 'Das ist ein strittiges Thema in der Gesellschaft.', 'This is a controversial topic in society.', 6);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Konjunktiv II Vergangenheit', 'Der Konjunktiv II Vergangenheit drückt irreale Situationen in der Vergangenheit aus – Dinge, die nicht passiert sind, aber hätten passieren können. Bildung: "hätte/wäre" + Partizip Perfekt. "Hätte" für die meisten Verben, "wäre" für Bewegungs- und Zustandsverben.', '[{"rule":"Bildung: hätte/wäre (konjugiert) + Partizip Perfekt","note":"Ich hätte gearbeitet. Wir wären gekommen."},{"rule":"\"hätte\" für Verben, die im Perfekt \"haben\" nehmen.","note":"Ich hätte das gemacht. (habe gemacht -> hätte gemacht)"},{"rule":"\"wäre\" für Verben, die im Perfekt \"sein\" nehmen.","note":"Wir wären gefahren. (sind gefahren -> wären gefahren)"},{"rule":"Modalverben im Konjunktiv II Vergangenheit: hätte + Infinitiv + Modalverb im Infinitiv.","note":"Ich hätte kommen können. (doppelter Infinitiv)"},{"rule":"Drückt Bedauern oder irreale Bedingungen in der Vergangenheit aus.","note":"Wenn ich mehr gelernt hätte, hätte ich die Prüfung bestanden."}]', '[{"german":"Ich hätte mehr Deutsch lernen sollen, bevor ich nach Deutschland kam.","arabic":"كان يجب أن أتعلم المزيد من الألمانية قبل أن آتي إلى ألمانيا.","english":"I should have learned more German before I came to Germany."},{"german":"Wenn wir früher losgefahren wären, hätten wir den Zug nicht verpasst.","arabic":"لو انطلقنا مبكراً، لما فاتنا القطار.","english":"If we had left earlier, we would not have missed the train."},{"german":"Er hätte die Stelle bekommen können, wenn er sich besser vorbereitet hätte.","arabic":"كان بإمكانه الحصول على الوظيفة لو أنه استعد بشكل أفضل.","english":"He could have gotten the job if he had prepared better."},{"german":"Ich wäre gern bei der Konferenz dabei gewesen.","arabic":"كنت أود أن أكون حاضراً في المؤتمر.","english":"I would have liked to be at the conference."},{"german":"Das hätte man anders machen sollen.","arabic":"كان يجب أن يتم ذلك بطريقة مختلفة.","english":"That should have been done differently."}]', '[{"mistake":"Wenn ich Zeit hätte, ich wäre gekommen.","correction":"Wenn ich Zeit gehabt hätte, wäre ich gekommen.","explanation":"Vergangenheit braucht Konjunktiv II Vergangenheit: \"hätte gehabt\"."},{"mistake":"Ich hätte kommen gekonnt.","correction":"Ich hätte kommen können.","explanation":"Doppelter Infinitiv: Modalverb bleibt im Infinitiv (nicht Partizip)."},{"mistake":"Wir wären gegangen, wenn wir die Tickets hätten.","correction":"Wir wären gegangen, wenn wir die Tickets gehabt hätten.","explanation":"\"Wenn\" + Plusquamperfekt Konjunktiv II für irreale Vergangenheit."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Wenn ich mehr Zeit _____, wäre ich gekommen. (haben - Konjunktiv II Vergangenheit)', '["gehabt hätte","hätte","habe","hatte"]', 'gehabt hätte', 'Konjunktiv II Vergangenheit: hätte + Partizip.', 1, 1),
  (l_id, 'multiple_choice', 'Was drückt der Konjunktiv II Vergangenheit aus?', '["Eine reale Möglichkeit","Eine irreal nicht eingetretene Vergangenheit","Eine zukünftige Handlung","Eine Tatsache"]', 'Eine irreal nicht eingetretene Vergangenheit', 'Der Konjunktiv II Vergangenheit drückt Irreales in der Vergangenheit aus.', 1, 2),
  (l_id, 'fill_gap', 'Wir _____ gern zur Party _____. (kommen - Konjunktiv II Vergangenheit)', '["hätten ... kommen","wären ... gekommen","hätten ... gekommen","wären ... kommen"]', 'wären ... gekommen', '"Kommen" ist ein Verb der Bewegung -> "wären ... gekommen".', 1, 3),
  (l_id, 'translation', 'Übersetze: "I would have helped you."', '["Ich hätte dir geholfen.","Ich würde dir helfen.","Ich habe dir geholfen.","Ich werde dir helfen."]', 'Ich hätte dir geholfen.', 'Konjunktiv II Vergangenheit: hätte + geholfen.', 1, 4),
  (l_id, 'multiple_choice', 'Welche Form ist korrekt? "Er _____ kommen können."', '["hätte","wäre","hat","ist"]', 'hätte', 'Modalverben im Konjunktiv II Vergangenheit: "hätte" + Infinitiv + Modalverb.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die These"?', '["الفرضية","الحجة","المناقشة","الاستنتاج"]', 'الفرضية', 1, 1),
  (l_id, 'true_false', 'Der Konjunktiv II Vergangenheit drückt Irreales aus.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Wenn du mich _____, hätte ich geholfen. (fragen - Konjunktiv II Vergangenheit)', '["gefragt hättest","fragtest","fragst","fragen würdest"]', 'gefragt hättest', 1, 3),
  (l_id, 'multiple_choice', '"Er hätte kommen können" bedeutet:', '["كان يمكنه أن يأتي (لكنه لم يأت)","يستطيع أن يأتي","سوف يأتي","أتى بالفعل"]', 'كان يمكنه أن يأتي (لكنه لم يأت)', 1, 4),
  (l_id, 'multiple_choice', 'Was ist "die Argumentation"?', '["الترجمة","الجدال/تقديم الحجج","الوصف","السرد"]', 'الجدال/تقديم الحجج', 1, 5),
  (l_id, 'fill_blank', 'Wir _____ gern mitgekommen. (wären)', '["wären","hätten","hatten","würden"]', 'wären', 1, 6);
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'wünschen', 'يتمنى', 'to wish', NULL, NULL, 'verb', 'Ich wünsche mir, dass der Krieg endet.', 'I wish that the war ends.', 1),
  (l_id, 'die Sehnsucht', 'الشوق/الحنين', 'longing', 'die', 'die Sehnsüchte', 'noun', 'Er hat Sehnsucht nach seiner Heimat.', 'He longs for his homeland.', 2),
  (l_id, 'die Hoffnung', 'الأمل', 'hope', 'die', 'die Hoffnungen', 'noun', 'Die Hoffnung auf eine bessere Zukunft stirbt zuletzt.', 'Hope for a better future is the last to die.', 3),
  (l_id, 'befürchten', 'يخشى/يخاف', 'to fear', NULL, NULL, 'verb', 'Ich befürchte, dass sich die Lage verschlechtern wird.', 'I fear that the situation will worsen.', 4),
  (l_id, 'die Vorstellung', 'التصور/الفكرة', 'idea/concept', 'die', 'die Vorstellungen', 'noun', 'Meine Vorstellung von der Zukunft ist positiv.', 'My idea of the future is positive.', 5),
  (l_id, 'ideal', 'مثالي', 'ideal', NULL, NULL, 'adjective', 'In einer idealen Welt gäbe es keinen Hunger.', 'In an ideal world there would be no hunger.', 6);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Irreale Wunschsätze', 'Irreale Wunschsätze drücken Wünsche aus, die unwahrscheinlich oder unmöglich sind. Sie werden mit Konjunktiv II gebildet. Typische Signalwörter: "wenn" oder Verb am Satzanfang, oft begleitet von "nur" oder "doch".', '[{"rule":"Irrealer Wunsch in der Gegenwart: \"Wenn\" + Konjunktiv II, Hauptsatz mit \"würde\" oder Konjunktiv II.","note":"Wenn ich mehr Zeit hätte, würde ich verreisen."},{"rule":"Verkürzter Wunschsatz: Konjunktiv II + \"nur\" oder \"doch\".","note":"Hätte ich doch mehr Geld! / Wäre ich nur zu Hause!"},{"rule":"Irrealer Wunsch in der Vergangenheit: Konjunktiv II Vergangenheit.","note":"Wenn ich das gewusst hätte! / Hätte ich das nur gewusst!"},{"rule":"Mit \"doch\" drückt man einen starken Wunsch oder Bedauern aus.","note":"Wäre sie doch hier geblieben!"},{"rule":"Mit \"nur\" betont man die Irrealität des Wunsches.","note":"Wenn es nur nicht so kompliziert wäre!"}]', '[{"german":"Wenn ich doch mehr Zeit hätte, würde ich öfter reisen.","arabic":"ليتني أملك وقتاً أكثر، لسافرت أكثر.","english":"If only I had more time, I would travel more often."},{"german":"Hätte ich doch mehr Deutsch gelernt, bevor ich nach Deutschland kam!","arabic":"ليتني تعلمت المزيد من الألمانية قبل مجيئي إلى ألمانيا!","english":"If only I had learned more German before coming to Germany!"},{"german":"Wenn es nur nicht so viel regnen würde!","arabic":"ليت المطر لا يهطل بغزارة!","english":"If only it would not rain so much!"},{"german":"Wäre ich doch bei der Konferenz dabeigewesen!","arabic":"ليتني كنت حاضراً في المؤتمر!","english":"If only I had been at the conference!"},{"german":"Wenn er sich doch besser vorbereitet hätte!","arabic":"ليته استعد بشكل أفضل!","english":"If only he had prepared better!"}]', '[{"mistake":"Wenn ich Zeit hätte, würde ich reisen. (als Wunsch korrekt, aber schwach)","correction":"Wenn ich doch Zeit hätte, würde ich reisen. / Hätte ich doch Zeit!","explanation":"\"Doch\" verstärkt den Wunsch und macht ihn emotionaler."},{"mistake":"Würde ich nur mehr Geld haben!","correction":"Hätte ich nur mehr Geld!","explanation":"Bei \"haben\" verwendet man im verkürzten Wunschsatz \"hätte\", nicht \"würde haben\"."},{"mistake":"Wenn ich das gewusst hätte, ich wäre nicht gekommen.","correction":"Wenn ich das gewusst hätte, wäre ich nicht gekommen.","explanation":"Im Hauptsatz nach dem Nebensatz steht das Verb an Position 1 (wäre)."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', '_____ ich doch mehr Geld! (haben - verkürzter Wunsch)', '["Hätte","Habe","Hatten","Würde haben"]', 'Hätte', 'Verkürzter Wunschsatz: "Hätte ich doch ...".', 1, 1),
  (l_id, 'multiple_choice', 'Was drückt "doch" in einem Wunschsatz aus?', '["Zweifel","Verstärkung des Wunsches","Zeit","Grund"]', 'Verstärkung des Wunsches', '"Doch" verstärkt die emotionale Bedeutung des Wunsches.', 1, 2),
  (l_id, 'translation', 'Übersetze: "If only I had known that!"', '["Wenn ich das nur wüsste!","Hätte ich das nur gewusst!","Wüsste ich das doch!","Wenn ich das wüsste!"]', 'Hätte ich das nur gewusst!', 'Vergangenheitswunsch: "Hätte ... gewusst".', 1, 3),
  (l_id, 'fill_gap', 'Wenn es _____ nicht so kalt _____, würden wir spazieren gehen. (nur/wäre)', '["nur ... wäre","doch ... wäre","nur ... würde","doch ... würde"]', 'nur ... wäre', 'Irrealer Wunsch mit "wenn" + "nur" + Konjunktiv II.', 1, 4),
  (l_id, 'multiple_choice', 'Welcher Satz drückt einen starken Wunsch aus?', '["Ich möchte mehr Zeit haben.","Hätte ich doch mehr Zeit!","Ich werde mehr Zeit haben.","Ich hatte mehr Zeit."]', 'Hätte ich doch mehr Zeit!', 'Der verkürzte Wunschsatz mit "doch" drückt den stärksten Wunsch aus.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Sehnsucht"?', '["الأمل","الشوق","الخوف","الفرح"]', 'الشوق', 1, 1),
  (l_id, 'true_false', '"Hätte ich doch mehr Zeit!" ist ein verkürzter Wunschsatz.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', '_____ ich nur mehr Geld gehabt! (haben - Vergangenheit)', '["Hätte","Habe","Hatte","Würde haben"]', 'Hätte', 1, 3),
  (l_id, 'multiple_choice', 'Welches Wort verstärkt einen Wunsch?', '["nur","doch","beide","keins"]', 'beide', 1, 4),
  (l_id, 'true_false', '"Wenn ich nur mehr Zeit hätte!" ist ein irrealer Wunsch.', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'multiple_choice', 'Was bedeutet "ideal" auf Arabisch?', '["مثالي","حقيقي","ممكن","صعب"]', 'مثالي', 1, 6);
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'effizient', 'فعال/كفوء', 'efficient', NULL, NULL, 'adjective', 'Je effizienter wir arbeiten, desto schneller sind wir fertig.', 'The more efficiently we work, the faster we are done.', 1),
  (l_id, 'gründlich', 'دقيق/بإتقان', 'thorough', NULL, NULL, 'adjective', 'Je gründlicher du recherchierst, desto besser wird die Arbeit.', 'The more thoroughly you research, the better the work will be.', 2),
  (l_id, 'überzeugen', 'يقنع', 'to convince', NULL, NULL, 'verb', 'Seine Argumente konnten die Zuhörer überzeugen.', 'His arguments were able to convince the audience.', 3),
  (l_id, 'die Konsequenz', 'النتيجة/العاقبة', 'consequence', 'die', 'die Konsequenzen', 'noun', 'Jede Entscheidung hat Konsequenzen.', 'Every decision has consequences.', 4),
  (l_id, 'der Zusammenhang', 'العلاقة/الارتباط', 'context/connection', 'der', 'die Zusammenhänge', 'noun', 'Es gibt einen Zusammenhang zwischen Bildung und Wohlstand.', 'There is a connection between education and prosperity.', 5);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Je...desto/umso und erweiterte Infinitivsätze', 'Die Struktur "je...desto/umso" drückt proportionale Vergleiche aus. "Ohne...zu" + Infinitiv drückt aus, dass eine Handlung nicht stattfindet, während eine andere geschieht. "Anstatt...zu" + Infinitiv drückt eine Ersatzhandlung aus.', '[{"rule":"Je...desto/umso: Je + Komparativ, desto/umso + Komparativ.","note":"Je mehr man lernt, desto mehr versteht man."},{"rule":"Je + Nebensatz (Verb am Ende), desto + Hauptsatz (Verb an Position 2).","note":"Je schneller wir arbeiten, desto früher sind wir fertig."},{"rule":"Ohne...zu + Infinitiv: Eine Handlung wird nicht ausgeführt.","note":"Er ging, ohne sich zu verabschieden."},{"rule":"Anstatt...zu + Infinitiv: Ersatz einer Handlung.","note":"Anstatt zu arbeiten, hat er ferngesehen."},{"rule":"Um...zu + Infinitiv: Zweckangabe (Abgrenzung zu ohne/anstatt).","note":"Sie spart Geld, um ein Auto zu kaufen."}]', '[{"german":"Je mehr man übt, desto besser wird man.","arabic":"كلما تدربت أكثر، أصبحت أفضل.","english":"The more you practice, the better you become."},{"german":"Je länger die Diskussion dauerte, umso hitziger wurde sie.","arabic":"كلما طالت المناقشة، أصبحت أكثر حدة.","english":"The longer the discussion lasted, the more heated it became."},{"german":"Er verließ das Meeting, ohne ein Wort zu sagen.","arabic":"غادر الاجتماع دون أن يقول كلمة واحدة.","english":"He left the meeting without saying a word."},{"german":"Anstatt den Fehler zuzugeben, hat er die Schuld auf andere geschoben.","arabic":"بدلاً من الاعتراف بالخطأ، ألقى اللوم على الآخرين.","english":"Instead of admitting the mistake, he blamed others."},{"german":"Je mehr Argumente er brachte, desto überzeugender wurde seine Präsentation.","arabic":"كلما قدم المزيد من الحجج، أصبح عرضه أكثر إقناعاً.","english":"The more arguments he brought, the more convincing his presentation became."}]', '[{"mistake":"Je mehr du arbeitest, desto du wirst müde.","correction":"Je mehr du arbeitest, desto müder wirst du.","explanation":"Nach \"desto\" braucht man den Komparativ und das Verb steht an Position 2."},{"mistake":"Ohne zu zögern, er hat geantwortet.","correction":"Er hat geantwortet, ohne zu zögern. / Ohne zu zögern, hat er geantwortet.","explanation":"Der Infinitivsatz mit \"ohne...zu\" kann vor oder nach dem Hauptsatz stehen."},{"mistake":"Anstatt zu arbeiten, er hat ferngesehen.","correction":"Anstatt zu arbeiten, hat er ferngesehen.","explanation":"Nach dem Infinitivsatz folgt das Verb an Position 1 (hat er)."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Je mehr man übt, _____ besser wird man. (desto)', '["desto","weil","obwohl","wenn"]', 'desto', 'Je...desto: proportionale Steigerung.', 1, 1),
  (l_id, 'multiple_choice', 'Welcher Satz ist korrekt mit "ohne...zu"?', '["Er ging ohne zu sagen etwas.","Er ging, ohne etwas zu sagen.","Er ging ohne etwas sagen.","Er ging ohne zu sagen."]', 'Er ging, ohne etwas zu sagen.', '"Ohne...zu" + Infinitiv mit Objekt dazwischen.', 1, 2),
  (l_id, 'translation', 'Übersetze: "Instead of studying, he watched TV."', '["Ohne zu lernen, hat er ferngesehen.","Anstatt zu lernen, hat er ferngesehen.","Um zu lernen, hat er ferngesehen.","Statt lernen, hat er ferngesehen."]', 'Anstatt zu lernen, hat er ferngesehen.', '"Anstatt...zu" drückt Ersatz aus.', 1, 3),
  (l_id, 'fill_gap', 'Je _____, desto besser. (schnell - Komparativ)', '["schnell","schneller","schnellste","am schnellsten"]', 'schneller', 'Je + Komparativ, desto + Komparativ.', 1, 4),
  (l_id, 'multiple_choice', 'Was ist die richtige Wortstellung nach "desto"?', '["Verb an Position 1","Verb an Position 2","Verb am Ende","Verb an Position 3"]', 'Verb an Position 2', 'Nach "desto" folgt ein Hauptsatz mit Verb an Position 2.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was drückt "je...desto" aus?', '["Zeitliche Abfolge","Proportionalen Vergleich","Grund","Gegensatz"]', 'Proportionalen Vergleich', 1, 1),
  (l_id, 'true_false', '"Ohne...zu" drückt eine nicht ausgeführte Handlung aus.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Je länger die Diskussion, _____ hitziger wurde sie. (desto)', '["desto","weil","denn","obwohl"]', 'desto', 1, 3),
  (l_id, 'multiple_choice', 'Was bedeutet "anstatt"?', '["بدلاً من","دون","بسبب","على الرغم من"]', 'بدلاً من', 1, 4),
  (l_id, 'true_false', 'Nach "je" steht das Verb am Satzende.', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'multiple_choice', 'Welcher Satz ist korrekt?', '["Anstatt arbeiten, er schläft.","Anstatt zu arbeiten, schläft er.","Anstatt arbeiten, schläft er.","Anstatt zu arbeiten, er schläft."]', 'Anstatt zu arbeiten, schläft er.', 1, 6);
