  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Pro-Contra-Debatte', 'مناقشة مؤيد معارض', 'pro-con debate', 'die', 'die Pro-Contra-Debatten', 'noun', 'In der Pro-Contra-Debatte wurden beide Seiten beleuchtet.', 'In the pro-con debate, both sides were examined.', 1),
  (l_id, 'die Position', 'الموقف', 'position', 'die', 'die Positionen', 'noun', 'Die Position der Regierung ist klar.', 'The government''s position is clear.', 2),
  (l_id, 'die Kritik', 'النقد', 'criticism', 'die', 'die Kritiken', 'noun', 'Es gab viel Kritik an dem Vorschlag.', 'There was a lot of criticism of the proposal.', 3),
  (l_id, 'der Einwand', 'الاعتراض', 'objection', 'der', 'die Einwände', 'noun', 'Haben Sie Einwände gegen diesen Plan?', 'Do you have any objections to this plan?', 4),
  (l_id, 'befürworten', 'يؤيد', 'to support/advocate', NULL, NULL, 'verb', 'Ich befürworte diese Maßnahme.', 'I support this measure.', 5),
  (l_id, 'ablehnen', 'يرفض', 'to reject', NULL, NULL, 'verb', 'Die Opposition lehnt den Gesetzesentwurf ab.', 'The opposition rejects the bill.', 6);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Konjunktiv II in Diskussionen und Argumentationen', 'In Diskussionen verwenden wir den Konjunktiv II häufig für höfliche Vorschläge (würde), irreale Bedingungen und kontrafaktische Argumente. "Ich würde sagen..." ist höflicher als "Ich sage...".', '[{"rule":"Höfliche Meinungsäußerung: \"Ich würde sagen/meinen/behaupten...\"","note":"Ich würde sagen, dass der Vorschlag sinnvoll ist."},{"rule":"Höflicher Vorschlag: \"Wir könnten... / Würden Sie...?\"","note":"Wir könnten das Problem anders angehen."},{"rule":"Irreale Bedingung in der Gegenwart: Wenn + Konjunktiv II, würde + Infinitiv.","note":"Wenn ich die Wahl hätte, würde ich dagegen stimmen."},{"rule":"Kontrafaktische Argumentation: \"Selbst wenn...würde...\"","note":"Selbst wenn der Preis stimmt, würde ich nicht zustimmen."}]', '[{"german":"Ich würde sagen, dass die Investition notwendig ist.","arabic":"أود القول إن الاستثمار ضروري.","english":"I would say that the investment is necessary."},{"german":"Wenn ich die Wahl hätte, würde ich für die Steuerreform stimmen.","arabic":"لو كان لدي الخيار، لصوتت لإصلاح الضرائب.","english":"If I had the choice, I would vote for the tax reform."},{"german":"Man hätte die Bürger früher informieren können.","arabic":"كان يمكن إعلام المواطنين في وقت مبكر.","english":"The citizens could have been informed earlier."},{"german":"Selbst wenn die Kosten steigen würden, wäre das Projekt sinnvoll.","arabic":"حتى لو ارتفعت التكاليف، سيكون المشروع مفيداً.","english":"Even if the costs were to rise, the project would make sense."}]', '[{"mistake":"Ich würde denke, dass es richtig ist.","correction":"Ich würde denken, dass es richtig ist. / Ich denke, dass es richtig ist.","explanation":"Nach \"würde\" kommt der Infinitiv, nicht die konjugierte Form."},{"mistake":"Wenn ich Zeit hätte, ich würde helfen.","correction":"Wenn ich Zeit hätte, würde ich helfen.","explanation":"Im Hauptsatz steht das konjugierte Verb an Position 1 (würde)."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Ich _____ sagen, dass die Reform notwendig ist. (würde)', '["würde","werde","wollte","könnte"]', 'würde', '"Ich würde sagen" ist eine höfliche Meinungsäußerung.', 1, 1),
  (l_id, 'multiple_choice', 'Welche Formulierung ist höflicher?', '["Das ist falsch.","Ich würde sagen, dass das nicht ganz stimmt.","Das stimmt nicht.","Sie irren sich."]', 'Ich würde sagen, dass das nicht ganz stimmt.', '"Ich würde sagen..." ist eine höfliche Abschwächung.', 1, 2),
  (l_id, 'translation', 'Übersetze: "If I were you, I would accept the offer."', '["Wenn ich du wäre, würde ich das Angebot annehmen.","Wenn ich du bin, nehme ich das Angebot an.","Wenn ich du war, nahm ich das Angebot an.","Wenn ich du sein werde, werde ich das Angebot annehmen."]', 'Wenn ich du wäre, würde ich das Angebot annehmen.', 'Irreale Bedingung: Konjunktiv II in beiden Satzteilen.', 1, 3),
  (l_id, 'fill_gap', 'Selbst _____ die Kosten steigen würden, wäre das Projekt sinnvoll. (wenn)', '["wenn","obwohl","weil","dass"]', 'wenn', '"Selbst wenn" leitet eine konzessive irreale Bedingung ein.', 1, 4),
  (l_id, 'multiple_choice', 'Was bedeutet "ablehnen" im politischen Kontext?', '["يقبل","يرفض","يقترح","يناقش"]', 'يرفض', '"Ablehnen" bedeutet "to reject".', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Kritik"?', '["النقد","القبول","الاقتراح","المناقشة"]', 'النقد', 1, 1),
  (l_id, 'true_false', '"Ich würde sagen" ist höflicher als "ich sage".', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Wenn ich mehr Zeit _____, würde ich helfen. (haben - Konjunktiv II)', '["hätte","habe","hatte","haben würde"]', 'hätte', 1, 3),
  (l_id, 'multiple_choice', 'Was bedeutet "befürworten"?', '["يؤيد","يرفض","ينتقد","يناقش"]', 'يؤيد', 1, 4),
  (l_id, 'true_false', 'Der Konjunktiv II kann für höfliche Vorschläge verwendet werden.', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'fill_blank', 'Man _____ die Bürger früher informieren können. (hätte)', '["hätte","wäre","hat","würde"]', 'hätte', 1, 6);
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Analyse', 'التحليل', 'analysis', 'die', 'die Analysen', 'noun', 'Eine gründliche Analyse ist die Basis jeder guten Argumentation.', 'A thorough analysis is the basis of any good argumentation.', 1),
  (l_id, 'die Schlussfolgerung', 'الاستنتاج', 'conclusion', 'die', 'die Schlussfolgerungen', 'noun', 'Welche Schlussfolgerung ziehen Sie daraus?', 'What conclusion do you draw from that?', 2),
  (l_id, 'die Bewertung', 'التقييم', 'evaluation', 'die', 'die Bewertungen', 'noun', 'Die Bewertung der Ergebnisse war positiv.', 'The evaluation of the results was positive.', 3),
  (l_id, 'die Perspektive', 'المنظور', 'perspective', 'die', 'die Perspektiven', 'noun', 'Aus meiner Perspektive ist die Situation anders.', 'From my perspective, the situation is different.', 4),
  (l_id, 'kontrovers', 'مثير للجدل', 'controversial', NULL, NULL, 'adjective', 'Das Thema wurde kontrovers diskutiert.', 'The topic was controversially discussed.', 5);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Wiederholung: Konjunktiv II, Irreale Wünsche, Je...desto und erweiterte Infinitivsätze', 'In dieser Wiederholung festigen wir alle Grammatikthemen aus Modul 2: den Konjunktiv II Vergangenheit für irreale Situationen, irreale Wunschsätze mit "doch/nur", proportionale Vergleiche mit "je...desto/umso" und erweiterte Infinitivsätze mit "ohne...zu" und "anstatt...zu".', '[{"rule":"Konjunktiv II Vergangenheit: hätte/wäre + Partizip Perfekt.","note":"Ich hätte geholfen. Wir wären gekommen."},{"rule":"Irreale Wunschsätze: Wenn + Konjunktiv II, Hauptsatz mit würde. Verkürzt: Hätte ich doch...!","note":"Wenn ich doch mehr Zeit hätte! / Hätte ich doch Urlaub!"},{"rule":"Je...desto/umso: proportionale Vergleiche, Komparativ in beiden Teilen.","note":"Je mehr, desto besser."},{"rule":"Ohne...zu + Infinitiv: Handlung unterbleibt. Anstatt...zu + Infinitiv: Ersatzhandlung.","note":"Ohne zu fragen, anstatt zu arbeiten."}]', '[{"german":"Ohne die gute Vorbereitung hätten wir die Prüfung nicht bestanden.","arabic":"بدون التحضير الجيد، لما كنا قد نجحنا في الامتحان.","english":"Without good preparation, we would not have passed the exam."},{"german":"Je kontroverser das Thema, desto hitziger wird die Diskussion.","arabic":"كلما كان الموضوع أكثر إثارة للجدل، أصبحت المناقشة أكثر حدة.","english":"The more controversial the topic, the more heated the discussion becomes."},{"german":"Anstatt zu diskutieren, sollten wir handeln.","arabic":"بدلاً من المناقشة، يجب أن نتحرك.","english":"Instead of discussing, we should take action."},{"german":"Hätte ich doch mehr auf meine Gesundheit geachtet!","arabic":"ليتني اهتممت بصحتي أكثر!","english":"If only I had taken better care of my health!"}]', '[{"mistake":"Wenn ich Zeit hätte, ich würde kommen.","correction":"Wenn ich Zeit hätte, würde ich kommen.","explanation":"Nach Nebensatz + Komma folgt Verb im Hauptsatz an Position 1."},{"mistake":"Je mehr man arbeitet, desto man wird müde.","correction":"Je mehr man arbeitet, desto müder wird man.","explanation":"Nach \"desto\" folgt Komparativ + Verb + Subjekt."},{"mistake":"Er ging ohne zu sagen nichts.","correction":"Er ging, ohne etwas zu sagen.","explanation":"\"Ohne etwas zu sagen\" – \"etwas\" steht vor \"zu\"."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Wir _____ gern mit dir gekommen. (sein - Konjunktiv II)', '["wären","hätten","würden","hatten"]', 'wären', '"Kommen" nimmt "sein": wären gekommen.', 1, 1),
  (l_id, 'multiple_choice', 'Welcher Satz enthält "je...desto"?', '["Je mehr ich lerne, desto mehr verstehe ich.","Weil ich lerne, verstehe ich mehr.","Obwohl ich lerne, verstehe ich wenig.","Wenn ich lerne, verstehe ich."]', 'Je mehr ich lerne, desto mehr verstehe ich.', 'Je...desto für proportionale Vergleiche.', 1, 2),
  (l_id, 'translation', 'Übersetze: "If only I had studied more!"', '["Hätte ich doch mehr gelernt!","Habe ich mehr gelernt!","Würde ich mehr lernen!","Wenn ich mehr lerne!"]', 'Hätte ich doch mehr gelernt!', 'Verkürzter Wunschsatz in der Vergangenheit.', 1, 3),
  (l_id, 'fill_gap', '_____ zu helfen, hat er zugeschaut. (Anstatt)', '["Anstatt","Statt","Ohne","Um"]', 'Anstatt', '"Anstatt...zu" drückt Ersatz einer Handlung aus.', 1, 4),
  (l_id, 'multiple_choice', 'Welche Struktur drückt eine nicht ausgeführte Handlung aus?', '["um...zu","ohne...zu","anstatt...zu","je...desto"]', 'ohne...zu', '"Ohne...zu" bedeutet, dass die Handlung nicht passiert ist.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Analyse"?', '["التحليل","التركيب","التقييم","المناقشة"]', 'التحليل', 1, 1),
  (l_id, 'true_false', 'Je...desto drückt einen Gegensatz aus.', '["Richtig","Falsch"]', 'Falsch', 1, 2),
  (l_id, 'fill_blank', 'Hätte ich _____ mehr Zeit gehabt! (doch)', '["doch","schon","noch","auch"]', 'doch', 1, 3),
  (l_id, 'multiple_choice', '"Anstatt zu arbeiten, hat er ferngesehen" bedeutet:', '["عمل وشاهد التلفاز","بدلاً من العمل، شاهد التلفاز","أثناء العمل، شاهد التلفاز","بعد العمل، شاهد التلفاز"]', 'بدلاً من العمل، شاهد التلفاز', 1, 4),
  (l_id, 'true_false', '"Wäre" wird für Verben der Bewegung im Konjunktiv II Vergangenheit verwendet.', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'multiple_choice', 'Was ist die korrekte Form? "_____ ich mehr gewusst!"', '["Hätte","Habe","Wäre","Würde"]', 'Hätte', 1, 6);
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Wenn ich das gewusst _____, wäre ich nicht gekommen. (haben - Konjunktiv II)', '["hätte","habe","hatte","haben würde"]', 'hätte', 'Konjunktiv II Vergangenheit: hätte gewusst.', 1, 1),
  (l_id, 'multiple_choice', 'Was drückt "Hätte ich doch mehr Zeit!" aus?', '["Einen Befehl","Einen irrealen Wunsch","Eine Tatsache","Eine Frage"]', 'Einen irrealen Wunsch', 'Verkürzter Wunschsatz mit "doch".', 1, 2),
  (l_id, 'translation', 'Übersetze: "The more you practice, the better you become."', '["Je mehr du übst, desto besser wirst du.","Wenn du übst, wirst du besser.","Weil du übst, wirst du besser.","Obwohl du übst, wirst du besser."]', 'Je mehr du übst, desto besser wirst du.', 'Je...desto für proportionale Vergleiche.', 1, 3),
  (l_id, 'multiple_choice', 'Welche Struktur ist korrekt?', '["Ohne zu etwas sagen","Ohne etwas zu sagen","Ohne sagen zu etwas","Ohne etwas sagen zu"]', 'Ohne etwas zu sagen', '"Ohne" + Objekt + "zu" + Infinitiv.', 1, 4),
  (l_id, 'fill_gap', 'Anstatt _____ arbeiten, hat er ferngesehen. (zu)', '["zu","um zu","ohne zu","statt zu"]', 'zu', '"Anstatt...zu" + Infinitiv: "Anstatt zu arbeiten".', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was ist "die Schlussfolgerung"?', '["المقدمة","الاستنتاج","الفرضية","المناقشة"]', 'الاستنتاج', 1, 1),
  (l_id, 'true_false', 'Nach "je" steht das Verb am Satzende.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', '_____ ich mehr Geld gehabt, wäre ich gereist. (hätte)', '["Hätte","Wenn","Wäre","Habe"]', 'Hätte', 1, 3),
  (l_id, 'multiple_choice', '"Ohne...zu" drückt aus:', '["Zweck","nicht ausgeführte Handlung","Ersatzhandlung","Folge"]', 'nicht ausgeführte Handlung', 1, 4),
  (l_id, 'true_false', '"Ich würde sagen" ist eine direkte Aussage.', '["Richtig","Falsch"]', 'Falsch', 1, 5),
  (l_id, 'multiple_choice', 'Was ist der Komparativ von "gut"?', '["besser","guter","gute","best"]', 'besser', 1, 6),
  (l_id, 'fill_blank', 'Je länger die Diskussion, _____ emotionaler wurde sie. (desto)', '["desto","so","dann","denn"]', 'desto', 1, 7),
  (l_id, 'multiple_choice', 'Was bedeutet "befürworten"?', '["يؤيد","يعارض","ينتقد","يحلل"]', 'يؤيد', 1, 8);
