  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Einleitung', 'المقدمة', 'introduction', 'die', 'die Einleitungen', 'noun', 'Die Einleitung sollte neugierig machen.', 'The introduction should arouse curiosity.', 1),
  (l_id, 'der Hauptteil', 'الجزء الرئيسي', 'main part', 'der', 'die Hauptteile', 'noun', 'Im Hauptteil werden die wichtigsten Punkte erläutert.', 'The main part explains the most important points.', 2),
  (l_id, 'der Schluss', 'الخاتمة', 'conclusion', 'der', 'die Schlüsse', 'noun', 'Zum Schluss fasse ich die wichtigsten Punkte zusammen.', 'In conclusion, I summarize the most important points.', 3),
  (l_id, 'die Folie', 'الشريحة', 'slide', 'die', 'die Folien', 'noun', 'Auf der nächsten Folie sehen Sie die Grafik.', 'On the next slide you can see the chart.', 4),
  (l_id, 'das Handout', 'النشرة/المطبوعة', 'handout', 'das', 'die Handouts', 'noun', 'Das Handout enthält die wichtigsten Informationen.', 'The handout contains the most important information.', 5),
  (l_id, 'die These', 'الأطروحة', 'thesis statement', 'die', 'die Thesen', 'noun', 'Die zentrale These meines Vortrags lautet ...', 'The central thesis of my presentation is ...', 6);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Nominalisierung von Verben', 'Im B2-Niveau ersetzen wir oft Verben durch Nomen, um formeller und präziser zu schreiben. Dies ist typisch für Präsentationen, wissenschaftliche Texte und Geschäftskommunikation. Aus "analysieren" wird "die Analyse", aus "entwickeln" wird "die Entwicklung".', '[{"rule":"Nominalisierung: Verb -> Nomen. Oft mit -ung, -tion, -e, oder Infinitiv als Nomen.","note":"analysieren -> die Analyse, entwickeln -> die Entwicklung"},{"rule":"-ung ist die häufigste Endung für Nominalisierungen von Verben.","note":"verbessern -> die Verbesserung, bearbeiten -> die Bearbeitung"},{"rule":"Der Infinitiv eines Verbs kann auch als Nomen (Neutrum) verwendet werden.","note":"das Lesen, das Schreiben, das Verstehen"},{"rule":"Nominalisierungen machen den Satz formeller und kompakter.","note":"Nach der Analyse der Daten (statt: Nachdem wir die Daten analysiert haben)"},{"rule":"Nominalstil ist typisch für wissenschaftliche und berufliche Texte.","note":"Die Erstellung des Berichts dauert lange."}]', '[{"german":"Die Analyse der Daten zeigt einen klaren Trend.","arabic":"يظهر تحليل البيانات اتجاهاً واضحاً.","english":"The analysis of the data shows a clear trend."},{"german":"Die Entwicklung neuer Technologien schreitet schnell voran.","arabic":"يتقدم تطوير التقنيات الجديدة بسرعة.","english":"The development of new technologies is progressing rapidly."},{"german":"Die Erstellung des Budgets erfordert viel Arbeit.","arabic":"يتطلب إعداد الميزانية الكثير من العمل.","english":"The preparation of the budget requires a lot of work."},{"german":"Die Verbesserung der Ergebnisse war unser Ziel.","arabic":"كان تحسين النتائج هدفنا.","english":"The improvement of the results was our goal."},{"german":"Das Verstehen komplexer Texte ist eine wichtige Fähigkeit.","arabic":"فهم النصوص المعقدة هو مهارة مهمة.","english":"Understanding complex texts is an important skill."}]', '[{"mistake":"Die analysieren der Daten war schwierig.","correction":"Die Analyse der Daten war schwierig.","explanation":"Nominalisierung von \"analysieren\" -> \"die Analyse\", nicht der Infinitiv."},{"mistake":"Die entwickeln neuer Produkte ist teuer.","correction":"Die Entwicklung neuer Produkte ist teuer.","explanation":"Nominalisierung: entwickeln -> die Entwicklung."},{"mistake":"Nach die Analyse der Daten haben wir entschieden.","correction":"Nach der Analyse der Daten haben wir entschieden.","explanation":"Nach \"nach\" + Dativ (der Analyse), nicht Akkusativ."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Die _____ der Daten war sehr aufwendig. (analysieren -> Nomen)', '["Analyse","Analysierung","Analysen","Analytik"]', 'Analyse', 'Nominalisierung von "analysieren" -> "die Analyse".', 1, 1),
  (l_id, 'multiple_choice', 'Welche Endung ist typisch für Nominalisierungen im Deutschen?', '["-heit","-ung","-keit","-schaft"]', '-ung', '-ung ist die häufigste Nominalisierungsendung (die Entwicklung, die Verbesserung).', 1, 2),
  (l_id, 'translation', 'Übersetze: "The preparation of the report takes time."', '["Der Bericht vorbereiten dauert Zeit.","Die Erstellung des Berichts dauert Zeit.","Das Bericht erstellen dauert Zeit.","Die Vorbereiten des Berichts dauert Zeit."]', 'Die Erstellung des Berichts dauert Zeit.', 'Nominalisierung: erstellen -> die Erstellung.', 1, 3),
  (l_id, 'fill_gap', 'Das _____ von Fachtexten erfordert Übung. (lesen)', '["Lesen","Lese","Lesung","Gelesen"]', 'Lesen', 'Infinitiv als Nomen (Neutrum): das Lesen.', 1, 4),
  (l_id, 'multiple_choice', 'Welche Nominalform ist korrekt für "verbessern"?', '["die Verbesserung","die Verbesser","das Verbessern","die Verbesserheit"]', 'die Verbesserung', 'Verbessern -> die Verbesserung (-ung).', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Einleitung"?', '["المقدمة","الخاتمة","الشريحة","الموضوع"]', 'المقدمة', 1, 1),
  (l_id, 'true_false', 'Nominalisierungen machen Sätze formeller.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Die _____ neuer Produkte ist teuer. (entwickeln -> Nomen)', '["Entwicklung","Entwickelung","Entwurf","Erstellung"]', 'Entwicklung', 1, 3),
  (l_id, 'multiple_choice', 'Was ist die Nominalform von "analysieren"?', '["die Analysierung","die Analyse","das Analysieren","der Analytiker"]', 'die Analyse', 1, 4),
  (l_id, 'true_false', 'Der Infinitiv kann als Nomen (Neutrum) verwendet werden.', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'multiple_choice', '"Der Hauptteil" einer Präsentation ist:', '["الجزء الرئيسي","الخاتمة","المقدمة","الملخص"]', 'الجزء الرئيسي', 1, 6);
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Grafik', 'الرسم البياني', 'chart/graphic', 'die', 'die Grafiken', 'noun', 'Die Grafik zeigt den Umsatzverlauf.', 'The chart shows the sales trend.', 1),
  (l_id, 'das Diagramm', 'المخطط البياني', 'diagram', 'das', 'die Diagramme', 'noun', 'Im Diagramm sind die Ergebnisse dargestellt.', 'The results are shown in the diagram.', 2),
  (l_id, 'der Anstieg', 'الارتفاع/الزيادة', 'increase', 'der', 'die Anstiege', 'noun', 'Der Anstieg der Verkaufszahlen ist beeindruckend.', 'The increase in sales figures is impressive.', 3),
  (l_id, 'der Rückgang', 'الانخفاض', 'decrease', 'der', 'die Rückgänge', 'noun', 'Es gab einen Rückgang der Produktion.', 'There was a decrease in production.', 4),
  (l_id, 'der Vergleich', 'المقارنة', 'comparison', 'der', 'die Vergleiche', 'noun', 'Im Vergleich zum Vorjahr ist der Umsatz gestiegen.', 'Compared to the previous year, sales have increased.', 5),
  (l_id, 'der Durchschnitt', 'المتوسط', 'average', 'der', 'die Durchschnitte', 'noun', 'Der Durchschnitt der Ergebnisse lag bei 85%.', 'The average of the results was 85%.', 6);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Präpositionalattribute: die Möglichkeit zu + Infinitiv', 'Präpositionalattribute erweitern Nominalphrasen und sind typisch für den formellen Sprachgebrauch. Die Struktur "Nomen + zu + Infinitiv" oder "Nomen + Präposition + Nomen" ermöglicht es, komplexe Informationen kompakt darzustellen.', '[{"rule":"Nomen + zu + Infinitiv: drückt eine Möglichkeit, Fähigkeit oder Notwendigkeit aus.","note":"die Möglichkeit zu lernen, die Fähigkeit zu kommunizieren"},{"rule":"Nomen + Präposition + Nomen: typische Präpositionen sind zu, für, von, mit, bei.","note":"die Entwicklung zu einem besseren System, die Fähigkeit zur Kommunikation"},{"rule":"Der Artikel richtet sich nach dem Nomen im Attribut (falls vorhanden).","note":"die Bedeutung der Analyse für das Projekt"},{"rule":"Präpositionalattribute ersetzen oft Nebensätze.","note":"Die Chance, den Vertrag zu bekommen (statt: die Chance, dass wir den Vertrag bekommen)"}]', '[{"german":"Wir haben die Möglichkeit, das Projekt zu finanzieren.","arabic":"لدينا الفرصة لتمويل المشروع.","english":"We have the opportunity to finance the project."},{"german":"Die Fähigkeit, komplexe Zusammenhänge zu erklären, ist wichtig.","arabic":"القدرة على شرح العلاقات المعقدة مهمة.","english":"The ability to explain complex relationships is important."},{"german":"Die Entwicklung zu einer nachhaltigen Wirtschaft ist unser Ziel.","arabic":"التطور نحو اقتصاد مستدام هو هدفنا.","english":"The development towards a sustainable economy is our goal."},{"german":"Die Bedeutung dieser Analyse für das Unternehmen ist groß.","arabic":"أهمية هذا التحليل للشركة كبيرة.","english":"The importance of this analysis for the company is great."},{"german":"Die Notwendigkeit, schneller zu reagieren, wurde deutlich.","arabic":"أصبحت ضرورة الاستجابة بشكل أسرع واضحة.","english":"The necessity to react faster became clear."}]', '[{"mistake":"Die Möglichkeit für das Projekt finanzieren.","correction":"Die Möglichkeit, das Projekt zu finanzieren.","explanation":"Nach \"Möglichkeit\" folgt \"zu + Infinitiv\" mit vorangestelltem Objekt."},{"mistake":"Wir haben die Chance um den Vertrag zu bekommen.","correction":"Wir haben die Chance, den Vertrag zu bekommen.","explanation":"Nach \"Chance\" kommt \"zu + Infinitiv\", nicht \"um...zu\"."},{"mistake":"Die Entwicklung der Firma zu internationale Märkte.","correction":"Die Entwicklung der Firma zu internationalen Märkten.","explanation":"Nach \"zu\" + Dativ: \"zu internationalen Märkten\"."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Wir haben die Möglichkeit, das Projekt _____ realisieren. (zu)', '["zu","um zu","für zu","von"]', 'zu', 'Präpositionalattribut mit "zu + Infinitiv".', 1, 1),
  (l_id, 'multiple_choice', 'Ergänze: "Die Fähigkeit, komplexe Texte _____ verstehen."', '["zu","um zu","für","von"]', 'zu', '"Fähigkeit, ... zu verstehen" – zu + Infinitiv.', 1, 2),
  (l_id, 'translation', 'Übersetze: "The opportunity to work abroad."', '["Die Möglichkeit, im Ausland zu arbeiten.","Die Möglichkeit für im Ausland arbeiten.","Die Chance um im Ausland arbeiten.","Die Gelegenheit für Ausland Arbeit."]', 'Die Möglichkeit, im Ausland zu arbeiten.', 'Präpositionalattribut: Möglichkeit + zu + Infinitiv.', 1, 3),
  (l_id, 'fill_gap', 'Die Entwicklung _____ einer besseren Lösung dauert noch. (zu)', '["zu","für","von","mit"]', 'zu', 'Die Entwicklung zu etwas (Dativ).', 1, 4),
  (l_id, 'multiple_choice', 'Was ist die korrekte Form? "Die Notwendigkeit, _____."', '["schneller zu reagieren","zu reagieren schneller","schneller reagieren","zu schnell reagieren"]', 'schneller zu reagieren', '"schneller" (Adverb) + "zu" + Infinitiv "reagieren".', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "der Anstieg"?', '["الانخفاض","الارتفاع","المقارنة","المتوسط"]', 'الارتفاع', 1, 1),
  (l_id, 'true_false', 'Präpositionalattribute ersetzen oft Nebensätze.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Wir haben die Chance, _____ Ausland zu arbeiten. (im)', '["im","in","am","ins"]', 'im', 1, 3),
  (l_id, 'multiple_choice', '"Der Rückgang" ist das Gegenteil von:', '["der Anstieg","der Vergleich","der Durchschnitt","die Grafik"]', 'der Anstieg', 1, 4),
  (l_id, 'true_false', 'Nach "zu" im Präpositionalattribut folgt der Infinitiv.', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'multiple_choice', 'Welche Präposition passt? "Die Entwicklung ___ einer besseren Lösung."', '["zu","von","für","mit"]', 'zu', 1, 6);
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'nämlich', 'وهو/أي أن', 'namely', NULL, NULL, 'adverb', 'Das Projekt war erfolgreich, nämlich aufgrund der guten Planung.', 'The project was successful, namely due to good planning.', 1),
  (l_id, 'und zwar', 'وبالتحديد', 'specifically/namely', NULL, NULL, 'conjunction', 'Wir haben ein Problem, und zwar ein finanzielles.', 'We have a problem, specifically a financial one.', 2),
  (l_id, 'einerseits...andererseits', 'من ناحية...من ناحية أخرى', 'on the one hand...on the other hand', NULL, NULL, 'adverb', 'Einerseits ist der Vorschlag gut, andererseits zu teuer.', 'On the one hand the proposal is good, on the other hand too expensive.', 3),
  (l_id, 'in Bezug auf', 'فيما يتعلق بـ', 'regarding', NULL, NULL, 'preposition', 'In Bezug auf Ihre Frage kann ich Folgendes sagen.', 'Regarding your question, I can say the following.', 4),
  (l_id, 'hinsichtlich', 'بخصوص/من حيث', 'with respect to', NULL, NULL, 'preposition', 'Hinsichtlich der Kosten müssen wir sparen.', 'With respect to costs, we need to save.', 5);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Textverknüpfung durch Konnektoren', 'Konnektoren verbinden Sätze und Abschnitte logisch miteinander. Für Präsentationen sind besonders wichtig: aufzählende Konnektoren (zunächst, dann, schließlich), begründende (nämlich, und zwar), einschränkende (allerdings, jedoch) und zusammenfassende (insgesamt, zusammenfassend).', '[{"rule":"Aufzählung: \"zunächst...dann...schließlich\" strukturieren den Vortrag.","note":"Zunächst stelle ich die Theorie vor, dann die Methodik."},{"rule":"Präzisierung: \"nämlich\" und \"und zwar\" erklären oder spezifizieren.","note":"Wir haben ein Problem, und zwar ein Zeitproblem."},{"rule":"Gegensatz: \"einerseits...andererseits\", \"allerdings\", \"jedoch\".","note":"Einerseits ist die Lösung effektiv, andererseits sehr teuer."},{"rule":"In Bezug auf / Hinsichtlich + Nomen: formaler Verweis auf ein Thema.","note":"Hinsichtlich der Finanzierung gibt es Klärungsbedarf."},{"rule":"Zusammenfassend/Insgesamt: Abschluss des Vortrags.","note":"Zusammenfassend lässt sich sagen, dass das Projekt erfolgreich war."}]', '[{"german":"Zunächst möchte ich die Ziele vorstellen. Danach folgt die Methodik. Schließlich präsentiere ich die Ergebnisse.","arabic":"أولاً أود تقديم الأهداف. بعد ذلك تتبع المنهجية. وأخيراً أقدم النتائج.","english":"First I would like to present the goals. Then the methodology follows. Finally I present the results."},{"german":"Die Präsentation war erfolgreich, und zwar dank der guten Vorbereitung.","arabic":"كان العرض التقديمي ناجحاً، وبالتحديد بفضل التحضير الجيد.","english":"The presentation was successful, specifically thanks to good preparation."},{"german":"Einerseits müssen wir Kosten sparen, andererseits in Qualität investieren.","arabic":"من ناحية يجب علينا توفير التكاليف، ومن ناحية أخرى الاستثمار في الجودة.","english":"On the one hand we need to save costs, on the other hand invest in quality."},{"german":"Hinsichtlich der nächsten Schritte empfehle ich ein Follow-up-Meeting.","arabic":"فيما يتعلق بالخطوات التالية، أوصي بعقد اجتماع متابعة.","english":"With respect to the next steps, I recommend a follow-up meeting."},{"german":"Zusammenfassend kann man sagen, dass das Projekt seine Ziele erreicht hat.","arabic":"بشكل عام، يمكن القول إن المشروع حقق أهدافه.","english":"In summary, one can say that the project achieved its goals."}]', '[{"mistake":"Und zwar, wir haben ein Problem.","correction":"Wir haben ein Problem, und zwar ein finanzielles.","explanation":"\"Und zwar\" leitet eine Präzisierung ein und steht nicht am Satzanfang."},{"mistake":"Hinsichtlich die Kosten müssen wir sparen.","correction":"Hinsichtlich der Kosten müssen wir sparen.","explanation":"\"Hinsichtlich\" regiert den Genitiv."},{"mistake":"Einerseits der Vorschlag ist gut, andererseits zu teuer.","correction":"Einerseits ist der Vorschlag gut, andererseits ist er zu teuer.","explanation":"Nach \"einerseits\" und \"andererseits\" folgt das Verb an Position 2."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', '_____ möchte ich die Ziele vorstellen. Dann die Methodik. (zunächst)', '["Zunächst","Schließlich","Danach","Zuletzt"]', 'Zunächst', '"Zunächst" leitet den ersten Punkt ein.', 1, 1),
  (l_id, 'multiple_choice', 'Welcher Ausdruck präzisiert eine Aussage?', '["einerseits","und zwar","schließlich","danach"]', 'und zwar', '"Und zwar" spezifiziert eine vorherige Aussage.', 1, 2),
  (l_id, 'translation', 'Übersetze: "On the one hand cheap, on the other hand low quality."', '["Einerseits billig, andererseits minderwertig.","Erstens billig, zweitens minderwertig.","Weder billig noch minderwertig.","Billig, und zwar minderwertig."]', 'Einerseits billig, andererseits minderwertig.', 'Gegensatz mit "einerseits...andererseits".', 1, 3),
  (l_id, 'fill_gap', '_____ der Kosten müssen wir sparen. (hinsichtlich)', '["Hinsichtlich","Hinsichtlich von","In Hinsicht auf","Hinsichtlich für"]', 'Hinsichtlich', '"Hinsichtlich" + Genitiv.', 1, 4),
  (l_id, 'multiple_choice', 'Welcher Konnektor eignet sich für den Abschluss einer Präsentation?', '["zunächst","zusammenfassend","nämlich","einerseits"]', 'zusammenfassend', '"Zusammenfassend" leitet die Schlussbemerkungen ein.', 1, 5);
