  (l_id, 'true_false', '"Hinsichtlich" regiert den Dativ.', '["Richtig","Falsch"]', 'Falsch', 1, 2),
  (l_id, 'fill_blank', '_____ ist die Lösung effektiv, andererseits teuer. (einerseits)', '["Einerseits","Erstens","Zum einen","Einesteils"]', 'Einerseits', 1, 3),
  (l_id, 'multiple_choice', 'Was ist die korrekte Reihenfolge in einer Präsentation?', '["Schluss -> Hauptteil -> Einleitung","Einleitung -> Hauptteil -> Schluss","Hauptteil -> Einleitung -> Schluss","Schluss -> Einleitung -> Hauptteil"]', 'Einleitung -> Hauptteil -> Schluss', 1, 4),
  (l_id, 'true_false', '"Und zwar" leitet eine Präzisierung ein.', '["Richtig","Falsch"]', 'Richtig', 1, 5),
