  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'der Redefluss', 'طلاقة الحديث', 'flow of speech', 'der', 'die Redeflüsse', 'noun', 'Ein guter Redefluss macht den Vortrag angenehm.', 'Good flow of speech makes the presentation pleasant.', 1),
  (l_id, 'die Betonung', 'التوكيد/النبر', 'emphasis', 'die', 'die Betonungen', 'noun', 'Die Betonung liegt auf den wichtigsten Punkten.', 'The emphasis is on the most important points.', 2),
  (l_id, 'das Publikum', 'الجمهور', 'audience', 'das', 'die Publika', 'noun', 'Das Publikum hat aufmerksam zugehört.', 'The audience listened attentively.', 3),
  (l_id, 'die Rückmeldung', 'التغذية الراجعة', 'feedback', 'die', 'die Rückmeldungen', 'noun', 'Ich freue mich auf Ihre Rückmeldung.', 'I look forward to your feedback.', 4),
  (l_id, 'die Körpersprache', 'لغة الجسد', 'body language', 'die', NULL, 'noun', 'Offene Körpersprache wirkt selbstbewusst.', 'Open body language appears confident.', 5),
  (l_id, 'der Blickkontakt', 'التواصل البصري', 'eye contact', 'der', NULL, 'noun', 'Halten Sie Blickkontakt mit dem Publikum.', 'Maintain eye contact with the audience.', 6);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Nominalisierung und Textverknüpfung in Vorträgen', 'In Vorträgen kombinieren wir Nominalisierungen (formeller Ausdruck) mit Textverknüpfung (Konnektoren für Struktur). Nominalisierungen machen den Vortrag professionell, Konnektoren helfen dem Publikum, der Struktur zu folgen.', '[{"rule":"Nominalisierungen für Fachbegriffe und Prozesse.","note":"die Entwicklung (statt entwickeln), die Analyse (statt analysieren)"},{"rule":"Konnektoren für die Struktur: zunächst, dann, danach, schließlich.","note":"Zunächst die Analyse, dann die Bewertung, schließlich die Entscheidung."},{"rule":"Präpositionalattribute für kompakte Informationen.","note":"Die Möglichkeit zur Optimierung des Prozesses."},{"rule":"Zusammenfassende Konnektoren für den Schluss.","note":"Insgesamt zeigt die Untersuchung, dass ..."}]', '[{"german":"Zunächst erfolgt die Analyse der aktuellen Situation.","arabic":"أولاً، يتم تحليل الوضع الحالي.","english":"First, the analysis of the current situation takes place."},{"german":"Die Implementierung dieser Maßnahme dauert drei Monate.","arabic":"تستغرق عملية تنفيذ هذا الإجراء ثلاثة أشهر.","english":"The implementation of this measure takes three months."},{"german":"Danach folgt die Bewertung der Ergebnisse.","arabic":"بعد ذلك يتبع تقييم النتائج.","english":"After that, the evaluation of the results follows."},{"german":"Hinsichtlich der Effizienz konnten wir eine Verbesserung feststellen.","arabic":"فيما يتعلق بالكفاءة، تمكنا من ملاحظة تحسن.","english":"With respect to efficiency, we were able to note an improvement."},{"german":"Zusammenfassend zeigt die Untersuchung positive Resultate.","arabic":"بشكل عام، يُظهر البحث نتائج إيجابية.","english":"In summary, the study shows positive results."}]', '[{"mistake":"Als erstes, ich analysiere die Daten.","correction":"Zunächst analysiere ich die Daten. / Als Erstes analysiere ich die Daten.","explanation":"\"Zunächst\" + Verb an Position 2 (kein Komma)."},{"mistake":"Die Bewerten der Daten war schwierig.","correction":"Die Bewertung der Daten war schwierig.","explanation":"Nominalisierung: bewerten -> die Bewertung, nicht der Infinitiv."},{"mistake":"Hinsichtlich die Kosten, wir müssen sparen.","correction":"Hinsichtlich der Kosten müssen wir sparen.","explanation":"\"Hinsichtlich\" + Genitiv + Verb direkt danach (kein Komma)."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Zunächst die _____ der Daten, dann die Auswertung. (analysieren -> Nomen)', '["Analyse","Analysierung","Analytik","Analysieren"]', 'Analyse', 'Nominalisierung: die Analyse.', 1, 1),
  (l_id, 'multiple_choice', 'Welche Struktur ist typisch für den Schluss eines Vortrags?', '["Zunächst möchte ich...","Zusammenfassend kann man sagen...","Einerseits...andererseits...","Und zwar..."]', 'Zusammenfassend kann man sagen...', '"Zusammenfassend" leitet die Zusammenfassung ein.', 1, 2),
  (l_id, 'translation', 'Übersetze: "First the analysis, then the evaluation."', '["Zuerst die Analyse, dann die Bewertung.","Erst Analyse, zweit Bewertung.","Anfangs Analyse, später Bewertung.","Analyse und Bewertung."]', 'Zuerst die Analyse, dann die Bewertung.', 'Strukturierung mit "zuerst...dann".', 1, 3),
  (l_id, 'fill_gap', 'Die _____ dieser Maßnahme dauert drei Monate. (implementieren -> Nomen)', '["Implementierung","Implementieren","Implement","Implementation"]', 'Implementierung', 'Implementieren -> die Implementierung.', 1, 4),
  (l_id, 'multiple_choice', 'Was ist wichtig für einen guten Vortrag?', '["Kein Blickkontakt","Blickkontakt mit dem Publikum","Nur die Folien lesen","Schnell sprechen"]', 'Blickkontakt mit dem Publikum', 'Blickkontakt ist ein wichtiges Element der Präsentation.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "das Publikum"?', '["الجمهور","المنصة","الشريحة","الميكروفون"]', 'الجمهور', 1, 1),
  (l_id, 'true_false', 'Nominalisierungen sind typisch für formelle Texte.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', '_____ zeigt die Untersuchung positive Resultate. (zusammenfassend)', '["Zusammenfassend","Zunächst","Danach","Nämlich"]', 'Zusammenfassend', 1, 3),
  (l_id, 'multiple_choice', 'Was bedeutet "die Rückmeldung"?', '["التسجيل","التغذية الراجعة","الاستفسار","الطلب"]', 'التغذية الراجعة', 1, 4),
  (l_id, 'true_false', 'Nach "hinsichtlich" kommt der Genitiv.', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'multiple_choice', 'Welcher Konnektor strukturiert eine Aufzählung?', '["nämlich","zunächst","allerdings","hinsichtlich"]', 'zunächst', 1, 6);
