  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Zusammenfassung', 'الملخص', 'summary', 'die', 'die Zusammenfassungen', 'noun', 'Die Zusammenfassung am Ende war sehr hilfreich.', 'The summary at the end was very helpful.', 1),
  (l_id, 'die Schlussfolgerung', 'الاستنتاج', 'conclusion', 'die', 'die Schlussfolgerungen', 'noun', 'Welche Schlussfolgerung ziehen Sie?', 'What conclusion do you draw?', 2),
  (l_id, 'die Darstellung', 'العرض/التمثيل', 'presentation/representation', 'die', 'die Darstellungen', 'noun', 'Die grafische Darstellung ist übersichtlich.', 'The graphical representation is clear.', 3),
  (l_id, 'die Strukturierung', 'الهيكلة/التنظيم', 'structuring', 'die', 'die Strukturierungen', 'noun', 'Eine gute Strukturierung ist das A und O.', 'Good structuring is the be-all and end-all.', 4),
  (l_id, 'der Vortrag', 'المحاضرة/العرض التقديمي', 'lecture/presentation', 'der', 'die Vorträge', 'noun', 'Der Vortrag war sehr informativ.', 'The lecture was very informative.', 5);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Wiederholung: Nominalisierung, Präpositionalattribute, Textverknüpfung', 'In dieser Wiederholung festigen wir die Nominalisierung von Verben (die Analyse, die Entwicklung), Präpositionalattribute (die Möglichkeit zu + Infinitiv) und die Textverknüpfung mit Konnektoren für Aufzählung, Präzisierung, Gegensatz und Zusammenfassung.', '[{"rule":"Nominalisierung: Verb -> Nomen. Häufig mit -ung.","note":"analysieren -> die Analyse, entwickeln -> die Entwicklung"},{"rule":"Präpositionalattribute: Nomen + zu + Infinitiv.","note":"die Möglichkeit zu lernen, die Fähigkeit zu reagieren"},{"rule":"Textverknüpfung: zunächst...dann...schließlich (Aufzählung).","note":"Zunächst die Analyse, dann die Bewertung, schließlich der Schluss."},{"rule":"Hinsichtlich + Genitiv: formaler Verweis.","note":"Hinsichtlich der Ergebnisse gibt es Neuigkeiten."}]', '[{"german":"Die Erstellung einer guten Präsentation erfordert sorgfältige Vorbereitung.","arabic":"يتطلب إعداد عرض تقديمي جيد تحضيراً دقيقاً.","english":"Creating a good presentation requires careful preparation."},{"german":"Die Fähigkeit, das Publikum zu begeistern, ist entscheidend.","arabic":"القدرة على إلهام الجمهور أمر حاسم.","english":"The ability to inspire the audience is crucial."},{"german":"Zunächst die Einleitung, dann der Hauptteil, schließlich der Schluss.","arabic":"أولاً المقدمة، ثم الجزء الرئيسي، وأخيراً الخاتمة.","english":"First the introduction, then the main part, finally the conclusion."}]', '[{"mistake":"Das Vortrag war gut.","correction":"Der Vortrag war gut.","explanation":"Der Vortrag ist maskulin, nicht Neutrum."},{"mistake":"Die analysieren der Daten dauerte lange.","correction":"Die Analyse der Daten dauerte lange.","explanation":"Nominalisierung: die Analyse, nicht der Infinitiv."},{"mistake":"Hinsichtlich die Finanzierung, es gibt Probleme.","correction":"Hinsichtlich der Finanzierung gibt es Probleme.","explanation":"\"Hinsichtlich\" + Genitiv, kein Komma."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Die _____ der Daten war einfach. (analysieren -> Nomen)', '["Analyse","Analysieren","Analytik","Analysation"]', 'Analyse', 'analysieren -> die Analyse.', 1, 1),
  (l_id, 'multiple_choice', 'Welche Struktur ist ein Präpositionalattribut?', '["schnell arbeiten","die Möglichkeit zu lernen","weil es regnet","der Mann dort"]', 'die Möglichkeit zu lernen', 'Nomen + zu + Infinitiv = Präpositionalattribut.', 1, 2),
  (l_id, 'translation', 'Übersetze: "In summary, the project was a success."', '["Zusammenfassend war das Projekt ein Erfolg.","Zunächst war das Projekt ein Erfolg.","Hinsichtlich des Projekts ein Erfolg.","Und zwar das Projekt war ein Erfolg."]', 'Zusammenfassend war das Projekt ein Erfolg.', '"Zusammenfassend" für den Abschluss.', 1, 3),
  (l_id, 'fill_gap', '_____ der Kosten müssen wir Alternativen prüfen. (hinsichtlich)', '["Hinsichtlich","Wegen","Trotz","Durch"]', 'Hinsichtlich', '"Hinsichtlich" + Genitiv.', 1, 4),
  (l_id, 'multiple_choice', 'Welche Endung ist typisch für die Nominalisierung?', '["-heit","-ung","-keit","-nis"]', '-ung', '-ung ist die häufigste Nominalisierungsendung.', 1, 5);
