  (l_id, 'true_false', '"Zunächst" leitet den ersten Punkt einer Aufzählung ein.', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'multiple_choice', 'Welches Wort passt? "Die _____, komplexe Sachverhalte zu erklären."', '["Fähigkeit","Fähigkeit zu","Möglichkeit für","Gelegenheit um"]', 'Fähigkeit', 1, 6);
