  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Terminologie', 'المصطلحات', 'terminology', 'die', 'die Terminologien', 'noun', 'Die medizinische Terminologie ist sehr komplex.', 'Medical terminology is very complex.', 1),
  (l_id, 'die Definition', 'التعريف', 'definition', 'die', 'die Definitionen', 'noun', 'Die Definition des Begriffs muss präzise sein.', 'The definition of the term must be precise.', 2),
  (l_id, 'die Klassifizierung', 'التصنيف', 'classification', 'die', 'die Klassifizierungen', 'noun', 'Die Klassifizierung der Daten erfolgt nach Kategorien.', 'The classification of the data is done by categories.', 3),
  (l_id, 'die Spezifikation', 'المواصفات', 'specification', 'die', 'die Spezifikationen', 'noun', 'Die technischen Spezifikationen müssen eingehalten werden.', 'The technical specifications must be complied with.', 4),
  (l_id, 'das Verfahren', 'الإجراء/الطريقة', 'procedure/method', 'das', 'die Verfahren', 'noun', 'Das Verfahren zur Datenerhebung wurde optimiert.', 'The data collection procedure was optimized.', 5),
  (l_id, 'die Validierung', 'التحقق من الصحة', 'validation', 'die', 'die Validierungen', 'noun', 'Die Validierung der Ergebnisse ist abgeschlossen.', 'The validation of the results is complete.', 6);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Funktionsverbgefüge', 'Funktionsverbgefüge sind feste Verbindungen aus einem Verb (oft mit schwacher Bedeutung) und einem Nomen (das die Hauptbedeutung trägt). Sie sind typisch für die formelle und technische Sprache. Beispiele: "zur Verfügung stellen" (bereitstellen), "in Betrieb nehmen" (starten).', '[{"rule":"Funktionsverbgefüge = Präposition (oder Nomen im Akk) + Funktionsverb.","note":"zur Verfügung stellen, in Kraft treten, zur Diskussion stellen"},{"rule":"Das Nomen trägt die Hauptbedeutung, das Verb ist grammatikalisch.","note":"zur Verfügung stellen = bereitstellen, in Betrieb nehmen = starten"},{"rule":"Funktionsverbgefüge machen den Text formeller und präziser.","note":"Die neue Software wird in Betrieb genommen. (statt: Die neue Software startet.)"},{"rule":"Typische Funktionsverben: bringen, kommen, stellen, nehmen, setzen, treten.","note":"zur Anwendung bringen, in Gang setzen, in Kraft treten"},{"rule":"Der Artikel des Nomens ist meist fest und nicht austauschbar.","note":"zur (nicht: zu der) Verfügung stellen, in (nicht: in die) Betrieb nehmen"}]', '[{"german":"Die neue Software wird in Betrieb genommen.","arabic":"سيتم تشغيل البرنامج الجديد.","english":"The new software is being put into operation."},{"german":"Der Vorsitzende stellt den Antrag zur Diskussion.","arabic":"يضع الرئيس الاقتراح للمناقشة.","english":"The chairman puts the motion up for discussion."},{"german":"Das neue Gesetz tritt am 1. Januar in Kraft.","arabic":"يدخل القانون الجديد حيز التنفيذ في 1 يناير.","english":"The new law comes into force on January 1st."},{"german":"Wir stellen Ihnen die Unterlagen zur Verfügung.","arabic":"نضع المستندات تحت تصرفكم.","english":"We make the documents available to you."},{"german":"Die Maschine wurde außer Betrieb gesetzt.","arabic":"تم إيقاف تشغيل الآلة.","english":"The machine was taken out of service."}]', '[{"mistake":"Wir stellen die Dokumente für Verfügung.","correction":"Wir stellen die Dokumente zur Verfügung.","explanation":"Es heißt \"zur Verfügung\" (zu + der -> zur), nicht \"für Verfügung\"."},{"mistake":"Das Gesetz tritt in die Kraft.","correction":"Das Gesetz tritt in Kraft.","explanation":"\"in Kraft\" ist eine feste Wendung ohne Artikel."},{"mistake":"Die neue Software wird in Betrieb genommen. (richtig) / nimmt Betrieb.","correction":"Die Wendung ist \"in Betrieb nehmen\", nicht \"Betrieb nehmen\".","explanation":"Das Nomen steht mit Präposition: in + Betrieb + nehmen."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Die neue Maschine wird in _____ genommen. (Betrieb)', '["Betrieb","die Betrieb","der Betrieb","Betrieben"]', 'Betrieb', 'Funktionsverbgefüge: in Betrieb nehmen (ohne Artikel).', 1, 1),
  (l_id, 'multiple_choice', 'Was bedeutet "zur Verfügung stellen"?', '["bereitstellen/وضع تحت التصرف","wegwerfen","verkaufen","suchen"]', 'bereitstellen/وضع تحت التصرف', 'Zur Verfügung stellen = verfügbar machen.', 1, 2),
  (l_id, 'translation', 'Übersetze: "The new law comes into force on Monday."', '["Das neue Gesetz tritt am Montag in Kraft.","Das neue Gesetz kommt am Montag in Kraft.","Das neue Gesetz nimmt am Montag in Kraft.","Das neue Gesetz setzt am Montag in Kraft."]', 'Das neue Gesetz tritt am Montag in Kraft.', 'Funktionsverbgefüge: in Kraft treten.', 1, 3),
  (l_id, 'fill_gap', 'Der Antrag wurde zur _____ gestellt. (Diskussion)', '["Diskussion","Diskutieren","Diskussions","Diskussionen"]', 'Diskussion', 'Zur Diskussion stellen = to put up for discussion.', 1, 4),
  (l_id, 'multiple_choice', 'Welches Funktionsverb passt? "_____ Sie mir bitte die Unterlagen zur Verfügung."', '["Stellen","Nehmen","Bringen","Setzen"]', 'Stellen', 'Zur Verfügung stellen = to make available.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Terminologie"?', '["المصطلحات","التعريف","التصنيف","الإجراء"]', 'المصطلحات', 1, 1),
  (l_id, 'true_false', 'Funktionsverbgefüge sind typisch für formelle Sprache.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Das neue Gesetz tritt am 1. Januar in _____. (Kraft)', '["Kraft","die Kraft","der Kraft","Kräften"]', 'Kraft', 1, 3),
  (l_id, 'multiple_choice', '"Zur Verfügung stellen" bedeutet:', '["يقدم/يضع تحت التصرف","يرفض","يطلب","يشتري"]', 'يقدم/يضع تحت التصرف', 1, 4),
  (l_id, 'true_false', 'In Funktionsverbgefügen trägt das Verb die Hauptbedeutung.', '["Richtig","Falsch"]', 'Falsch', 1, 5),
  (l_id, 'multiple_choice', 'Was ist ein Beispiel für ein Funktionsverbgefüge?', '["in Betrieb nehmen","schnell laufen","gut essen","viel trinken"]', 'in Betrieb nehmen', 1, 6);
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'der Prozess', 'العملية', 'process', 'der', 'die Prozesse', 'noun', 'Der Produktionsprozess wurde optimiert.', 'The production process was optimized.', 1),
  (l_id, 'die Optimierung', 'التحسين/الأمثلة', 'optimization', 'die', 'die Optimierungen', 'noun', 'Die Optimierung der Abläufe ist notwendig.', 'The optimization of processes is necessary.', 2),
  (l_id, 'die Automatisierung', 'الأتمتة', 'automation', 'die', 'die Automatisierungen', 'noun', 'Die Automatisierung der Fertigung spart Kosten.', 'The automation of manufacturing saves costs.', 3),
  (l_id, 'die Effizienz', 'الكفاءة', 'efficiency', 'die', 'die Effizienzen', 'noun', 'Die Effizienz der Produktion konnte gesteigert werden.', 'The efficiency of production could be increased.', 4),
  (l_id, 'die Schnittstelle', 'الواجهة/النقطة البينية', 'interface', 'die', 'die Schnittstellen', 'noun', 'Die Schnittstelle zwischen den Systemen funktioniert einwandfrei.', 'The interface between the systems works perfectly.', 5),
  (l_id, 'die Wartung', 'الصيانة', 'maintenance', 'die', 'die Wartungen', 'noun', 'Die regelmäßige Wartung der Anlagen ist vorgeschrieben.', 'Regular maintenance of the systems is mandatory.', 6);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Partizipialattribute', 'Partizipialattribute sind erweiterte Partizipien, die vor einem Nomen stehen und dieses näher beschreiben. Sie ersetzen Relativsätze und machen den Text kompakter. Partizip I (Aktiv, gleichzeitig): "der entwickelte" oder Partizip II (Passiv, abgeschlossen): "der entwickelte Prozess".', '[{"rule":"Partizip I (gleichzeitig, aktiv): Verb + -d + Adjektivendung.","note":"der entwickelnde Ingenieur (der Ingenieur, der entwickelt)"},{"rule":"Partizip II (abgeschlossen, passiv): ge- + Stamm + -t/-en + Adjektivendung.","note":"der entwickelte Prozess (der Prozess, der entwickelt wurde)"},{"rule":"Partizipialattribute können erweitert werden (mit Objekten/Adverbien).","note":"der von der Firma entwickelte Prozess"},{"rule":"Die Endung richtet sich nach Genus, Numerus und Kasus des Nomens.","note":"der entwickelte Prozess (Nom), des entwickelten Prozesses (Gen)"},{"rule":"Partizipialattribute ersetzen komplexe Relativsätze.","note":"der von einem Team entwickelte Prozess (statt: der Prozess, der von einem Team entwickelt wurde)"}]', '[{"german":"Der neu entwickelte Prozess verbessert die Effizienz.","arabic":"العملية المطورة حديثاً تحسن الكفاءة.","english":"The newly developed process improves efficiency."},{"german":"Die automatisch generierten Daten müssen validiert werden.","arabic":"يجب التحقق من البيانات التي تم إنشاؤها تلقائياً.","english":"The automatically generated data must be validated."},{"german":"Das von der Regierung verabschiedete Gesetz tritt bald in Kraft.","arabic":"القانون الذي أقرته الحكومة يدخل حيز التنفيذ قريباً.","english":"The law passed by the government will soon come into force."},{"german":"Die steigenden Energiekosten belasten die Industrie.","arabic":"تكاليف الطاقة المتزايدة تثقل كاهل الصناعة.","english":"The rising energy costs are burdening industry."},{"german":"Die für das Projekt verantwortlichen Mitarbeiter wurden informiert.","arabic":"الموظفون المسؤولون عن المشروع تم إبلاغهم.","english":"The employees responsible for the project were informed."}]', '[{"mistake":"Der entwickelte Prozess von der Firma.","correction":"Der von der Firma entwickelte Prozess.","explanation":"Das Partizipialattribut steht VOR dem Nomen. Die Erweiterung kommt vor dem Partizip."},{"mistake":"Die Daten generiert automatisch.","correction":"Die automatisch generierten Daten.","explanation":"Partizip + Adjektivendung vor dem Nomen, Adverb vor dem Partizip."},{"mistake":"Der entwickelnde Prozess (statt entwickelte).","correction":"Der entwickelte Prozess (Partizip II: abgeschlossen).","explanation":"Entwickelnd = gerade dabei (Partizip I), entwickelt = fertig (Partizip II)."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Der neu _____ Prozess verbessert die Effizienz. (entwickeln - Partizip II)', '["entwickelte","entwickelnde","entwickelte","entwickelter"]', 'entwickelte', 'Partizip II von entwickeln: entwickelt + e (Nominativ maskulin).', 1, 1),
  (l_id, 'multiple_choice', 'Was ersetzt ein Partizipialattribut?', '["Einen Hauptsatz","Einen Relativsatz","Einen Nebensatz mit \"weil\"","Einen Infinitivsatz"]', 'Einen Relativsatz', 'Partizipialattribute ersetzen Relativsätze.', 1, 2),
  (l_id, 'translation', 'Übersetze: "The newly developed software."', '["Die neu entwickelte Software","Die Software neu entwickelt","Die entwickelte neue Software","Neu die entwickelte Software"]', 'Die neu entwickelte Software', 'Partizipialattribut: Adverb + Partizip + Nomen.', 1, 3),
  (l_id, 'fill_gap', 'Die _____ Energiekosten sind ein Problem. (steigen - Partizip I)', '["steigenden","gestiegenen","steigende","gestiegene"]', 'steigenden', 'Partizip I (steigend) + en (Plural).', 1, 4),
  (l_id, 'multiple_choice', 'Welcher Satz kann durch ein Partizipialattribut ersetzt werden?', '["Der Prozess, der von der Firma entwickelt wurde.","Der Prozess ist effizient.","Der Prozess läuft gut.","Ich entwickle den Prozess."]', 'Der Prozess, der von der Firma entwickelt wurde.', 'Relativsatz -> Partizipialattribut: "Der von der Firma entwickelte Prozess".', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Optimierung"?', '["التحسين","الصيانة","الأتمتة","الكفاءة"]', 'التحسين', 1, 1),
  (l_id, 'true_false', 'Partizip I drückt eine gleichzeitige, aktive Handlung aus.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Die _____ (steigen) Kosten belasten die Wirtschaft.', '["steigenden","gestiegenen","steigende","gestiegene"]', 'steigenden', 1, 3),
  (l_id, 'multiple_choice', 'Partizipialattribute ersetzen:', '["Hauptsätze","Relativsätze","Fragesätze","Nebensätze mit \"weil\""]', 'Relativsätze', 1, 4),
  (l_id, 'true_false', 'Das Partizipialattribut steht nach dem Nomen.', '["Richtig","Falsch"]', 'Falsch', 1, 5),
  (l_id, 'multiple_choice', 'Was ist das Partizip II von "entwickeln"?', '["entwickelnd","entwickelt","entwickel","entwickelte"]', 'entwickelt', 1, 6);
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Berücksichtigung', 'المراعاة/الاعتبار', 'consideration', 'die', 'die Berücksichtigungen', 'noun', 'Unter Berücksichtigung aller Faktoren wurde entschieden.', 'Taking all factors into consideration, a decision was made.', 1),
  (l_id, 'die Durchführung', 'التنفيذ/الإجراء', 'implementation/execution', 'die', 'die Durchführungen', 'noun', 'Die Durchführung des Projekts liegt in Ihrer Verantwortung.', 'The implementation of the project is your responsibility.', 2),
  (l_id, 'die Abhängigkeit', 'الاعتمادية', 'dependency', 'die', 'die Abhängigkeiten', 'noun', 'Die Abhängigkeit von fossilen Brennstoffen muss reduziert werden.', 'The dependency on fossil fuels must be reduced.', 3),
  (l_id, 'die Wechselwirkung', 'التفاعل المتبادل', 'interaction/reciprocal effect', 'die', 'die Wechselwirkungen', 'noun', 'Die Wechselwirkung zwischen den Komponenten ist komplex.', 'The interaction between the components is complex.', 4),
  (l_id, 'die Rahmenbedingung', 'الشروط الإطارية', 'framework condition', 'die', 'die Rahmenbedingungen', 'noun', 'Die Rahmenbedingungen für das Projekt sind günstig.', 'The framework conditions for the project are favorable.', 5);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Komplexe Nominalphrasen', 'Komplexe Nominalphrasen bestehen aus einem Kern (Nomen) und mehreren Erweiterungen (Artikel, Adjektive, Partizipien, Genitivattribute, Präpositionalattribute). Sie sind typisch für die deutsche Fachsprache und ermöglichen extrem kompakte Aussagen.', '[{"rule":"Grundstruktur: (Erweiterungen) + Kern-Nomen + (nachgestellte Attribute).","note":"Die detaillierte Analyse des neu entwickelten Verfahrens"},{"rule":"Genitivattribute: Genitiv + Nomen oder Nomen + Genitiv.","note":"Die Analyse des Verfahrens / Des Verfahrens Analyse"},{"rule":"Mehrere Attribute können vor dem Kern stehen: Adjektiv, Partizip, Zahlwort.","note":"Die drei neu entwickelten, automatisierten Prozesse"},{"rule":"Nachgestellte Attribute: Präpositionalattribute, Relativsätze.","note":"die Analyse der Daten aus dem laufenden Projekt"},{"rule":"Die Nominalphrase kann einen ganzen Satz ersetzen.","note":"Die Berücksichtigung aller Faktoren ist notwendig. (statt: dass alle Faktoren berücksichtigt werden)"}]', '[{"german":"Die detaillierte Analyse des neu entwickelten Produktionsverfahrens.","arabic":"التحليل المفصل لعملية الإنتاج المطورة حديثاً.","english":"The detailed analysis of the newly developed production process."},{"german":"Die Optimierung der automatisierten Fertigungsprozesse.","arabic":"تحسين عمليات التصنيع المؤتمتة.","english":"The optimization of automated manufacturing processes."},{"german":"Die Berücksichtigung aller relevanten rechtlichen Rahmenbedingungen.","arabic":"مراعاة جميع الشروط الإطارية القانونية ذات الصلة.","english":"The consideration of all relevant legal framework conditions."},{"german":"Die steigende Abhängigkeit der Industrie von importierten Rohstoffen.","arabic":"الاعتماد المتزايد للصناعة على المواد الخام المستوردة.","english":"The industry''s growing dependence on imported raw materials."},{"german":"Die Durchführung der regelmäßigen Wartung der Produktionsanlagen.","arabic":"تنفيذ الصيانة الدورية لمنشآت الإنتاج.","english":"The implementation of regular maintenance of production facilities."}]', '[{"mistake":"Die neu entwickelte Verfahren.","correction":"Das neu entwickelte Verfahren.","explanation":"\"Verfahren\" ist Neutrum (das Verfahren), nicht feminin."},{"mistake":"Die Analyse des Verfahrens neu entwickelt.","correction":"Die Analyse des neu entwickelten Verfahrens.","explanation":"Adjektiv/Partizip steht vor dem Nomen, nicht danach."},{"mistake":"Die steigende Kosten der Produktion.","correction":"Die steigenden Kosten der Produktion.","explanation":"Kosten ist Plural -> steigenden (n-Deklination)."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Die detaillierte _____ des neuen Verfahrens. (analysieren -> Nomen)', '["Analyse","Analysieren","Analytik","Analysation"]', 'Analyse', 'Die Analyse (Nominalisierung von "analysieren").', 1, 1),
  (l_id, 'multiple_choice', 'Welcher Bestandteil ist der Kern einer komplexen Nominalphrase?', '["Das Adjektiv","Das Nomen","Das Verb","Der Artikel"]', 'Das Nomen', 'Der Kern ist immer das Nomen, um das alle Erweiterungen gruppiert sind.', 1, 2),
  (l_id, 'translation', 'Übersetze: "The consideration of all relevant factors."', '["Die Berücksichtigung aller relevanten Faktoren.","Die Berücksichtigen aller relevanten Faktoren.","Das Berücksichtigen von allen Faktoren.","Die Berücksichtigung von alle Faktoren."]', 'Die Berücksichtigung aller relevanten Faktoren.', 'Nominalphrase mit Genitivattribut + Adjektiv.', 1, 3),
  (l_id, 'fill_gap', 'Die _____ Kosten der Produktion sind ein Problem. (steigen - Partizip I)', '["steigenden","gestiegenen","steigende","gestiegene"]', 'steigenden', 'Plural + bestimmter Artikel: die steigenden Kosten.', 1, 4),
  (l_id, 'multiple_choice', 'Welche Phrase ist am kompaktesten?', '["Die Analyse der Daten aus dem aktuellen Projekt ist wichtig.","Es ist wichtig, dass wir die Daten aus dem aktuellen Projekt analysieren.","Wir müssen die Daten analysieren, die aus dem aktuellen Projekt kommen.","Datenanalyse des aktuellen Projektes ist wichtig."]', 'Die Analyse der Daten aus dem aktuellen Projekt ist wichtig.', 'Diese Nominalphrase ist präzise und kompakt.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Durchführung"?', '["التنفيذ","التحليل","التصنيف","الصيانة"]', 'التنفيذ', 1, 1),
  (l_id, 'true_false', 'Der Kern einer Nominalphrase ist das Nomen.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Die _____ (steigen) Energiekosten belasten die Wirtschaft.', '["steigenden","gestiegenen","steigende","gestiegene"]', 'steigenden', 1, 3),
  (l_id, 'multiple_choice', 'Was ist ein Genitivattribut?', '["des Verfahrens","dem Verfahren","das Verfahren","die Verfahren"]', 'des Verfahrens', 1, 4),
  (l_id, 'true_false', 'Fachsprache verwendet oft komplexe Nominalphrasen.', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'multiple_choice', 'Welche Wortart steht typischerweise vor dem Kern-Nomen?', '["Verb","Adjektiv/Partizip","Nomen im Dativ","Nebensatz"]', 'Adjektiv/Partizip', 1, 6);
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Dokumentation', 'التوثيق', 'documentation', 'die', 'die Dokumentationen', 'noun', 'Die technische Dokumentation muss vollständig sein.', 'The technical documentation must be complete.', 1),
  (l_id, 'die Richtlinie', 'التوجيه/الدليل الإرشادي', 'guideline', 'die', 'die Richtlinien', 'noun', 'Die Richtlinien für die Qualitätssicherung wurden aktualisiert.', 'The guidelines for quality assurance were updated.', 2),
  (l_id, 'die Norm', 'المعيار/المواصفة القياسية', 'standard', 'die', 'die Normen', 'noun', 'Die Produktion erfolgt nach europäischen Normen.', 'Production takes place according to European standards.', 3),
  (l_id, 'die Zertifizierung', 'الشهادة/الاعتماد', 'certification', 'die', 'die Zertifizierungen', 'noun', 'Die Zertifizierung nach ISO 9001 ist abgeschlossen.', 'The ISO 9001 certification is complete.', 4),
  (l_id, 'die Analyse', 'التحليل', 'analysis', 'die', 'die Analysen', 'noun', 'Die Analyse der Daten zeigt Verbesserungspotenzial.', 'The analysis of the data shows potential for improvement.', 5);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Funktionsverbgefüge und Partizipialattribute in Fachtexten', 'In Fachtexten treten Funktionsverbgefüge und Partizipialattribute besonders häufig auf. Funktionsverbgefüge ersetzen einfache Verben (zur Durchführung bringen = durchführen). Partizipialattribute ersetzen Relativsätze (das durchgeführte Verfahren = das Verfahren, das durchgeführt wurde).', '[{"rule":"Funktionsverbgefüge in technischen Texten: in Betrieb nehmen, zur Anwendung bringen.","note":"Das Verfahren wird zur Anwendung gebracht."},{"rule":"Partizipialattribute mit Erweiterungen: Adverbien und Objekte.","note":"Das von der Firma neu entwickelte und bereits getestete Verfahren"},{"rule":"Kombination beider Strukturen für extreme Kompaktheit.","note":"Die in Betrieb genommene, neu zertifizierte Anlage"},{"rule":"Typische Genitivketten in der Fachsprache.","note":"Die Durchführung der Optimierung des Verfahrens"}]', '[{"german":"Die in Betrieb genommene Anlage erfüllt alle Normen.","arabic":"المنشأة التي تم تشغيلها تفي بجميع المعايير.","english":"The facility put into operation meets all standards."},{"german":"Die zur Anwendung gebrachte Methodik wurde validiert.","arabic":"المنهجية التي تم تطبيقها تم التحقق من صحتها.","english":"The methodology that was applied was validated."},{"german":"Die Optimierung des neu entwickelten Produktionsverfahrens ist abgeschlossen.","arabic":"تحسين عملية الإنتاج المطورة حديثاً اكتمل.","english":"The optimization of the newly developed production process is complete."},{"german":"Das nach ISO 9001 zertifizierte Unternehmen expandiert.","arabic":"الشركة الحاصلة على شهادة ISO 9001 تتوسع.","english":"The company certified according to ISO 9001 is expanding."}]', '[{"mistake":"Die Anlage in Betrieb genommen wurde zertifiziert.","correction":"Die in Betrieb genommene Anlage wurde zertifiziert.","explanation":"Partizipialattribut + Nomen + Verb: Die in Betrieb genommene Anlage wurde ..."},{"mistake":"Die Analyse des Verfahrens wurde zur Durchführung gebracht.","correction":"Die Analyse des Verfahrens wurde durchgeführt.","explanation":"Einfacher: \"durchgeführt\" statt \"zur Durchführung gebracht\". Funktionsverbgefüge nicht immer nötig."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Die in _____ genommene Anlage läuft stabil. (Betrieb)', '["Betrieb","der Betrieb","die Betrieb","Betrieben"]', 'Betrieb', 'Funktionsverbgefüge: in Betrieb nehmen.', 1, 1),
  (l_id, 'multiple_choice', 'Was kennzeichnet einen Fachtext?', '["Umgangssprache","Viele Funktionsverbgefüge","Kurze Sätze","Nur Verben"]', 'Viele Funktionsverbgefüge', 'Fachtexte verwenden häufig Funktionsverbgefüge und Nominalisierungen.', 1, 2),
  (l_id, 'translation', 'Übersetze: "The newly developed and certified process."', '["Der neu entwickelte und zertifizierte Prozess.","Der entwickelte neue und zertifizierte Prozess.","Der Prozess neu entwickelt und zertifiziert.","Neu der entwickelte zertifizierte Prozess."]', 'Der neu entwickelte und zertifizierte Prozess.', 'Reihenfolge: Adverb + Partizip + Partizip + Nomen.', 1, 3),
  (l_id, 'fill_gap', 'Die nach ISO 9001 _____ Unternehmen sind erfolgreicher. (zertifizieren - Partizip II)', '["zertifizierten","zertifizierende","zertifizierte","zertifizierter"]', 'zertifizierten', 'Plural: die zertifizierten Unternehmen.', 1, 4),
  (l_id, 'multiple_choice', 'Welches Funktionsverbgefüge passt? "Die Software wurde in _____ genommen."', '["Betrieb","Kraft","Gang","Anwendung"]', 'Betrieb', 'In Betrieb nehmen = starten/in Betrieb setzen.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Zertifizierung"?', '["الشهادة/الاعتماد","التحليل","الصيانة","التصنيف"]', 'الشهادة/الاعتماد', 1, 1),
  (l_id, 'true_false', 'Fachtexte verwenden oft komplexe Nominalphrasen.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Die zur _____ gebrachte Methodik war erfolgreich. (Anwendung)', '["Anwendung","Anwend","Anwenden","Anwendungen"]', 'Anwendung', 1, 3),
  (l_id, 'multiple_choice', 'Ein Partizipialattribut ersetzt:', '["Einen Relativsatz","Einen Hauptsatz","Einen Fragesatz","Einen Befehlssatz"]', 'Einen Relativsatz', 1, 4),
  (l_id, 'true_false', '"In Betrieb nehmen" ist ein Funktionsverbgefüge.', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'multiple_choice', 'Was ist der Kern der Nominalphrase "die detaillierte Analyse des Verfahrens"?', '["detaillierte","Analyse","Verfahrens","die"]', 'Analyse', 1, 6);
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Implementierung', 'التنفيذ/التركيب', 'implementation', 'die', 'die Implementierungen', 'noun', 'Die Implementierung der neuen Software läuft.', 'The implementation of the new software is running.', 1),
  (l_id, 'die Integration', 'التكامل/الدمج', 'integration', 'die', 'die Integrationen', 'noun', 'Die Integration der Systeme war erfolgreich.', 'The integration of the systems was successful.', 2),
  (l_id, 'die Konfiguration', 'التكوين/الإعداد', 'configuration', 'die', 'die Konfigurationen', 'noun', 'Die Konfiguration des Netzwerks wurde aktualisiert.', 'The network configuration was updated.', 3),
  (l_id, 'die Migration', 'الترحيل/النقل', 'migration', 'die', 'die Migrationen', 'noun', 'Die Migration der Daten in die Cloud ist abgeschlossen.', 'The migration of data to the cloud is complete.', 4),
  (l_id, 'die Aktualisierung', 'التحديث', 'update', 'die', 'die Aktualisierungen', 'noun', 'Die Aktualisierung der Software ist erforderlich.', 'The software update is required.', 5);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Wiederholung: Funktionsverbgefüge, Partizipialattribute, komplexe Nominalphrasen', 'In dieser Wiederholung festigen wir die drei Hauptthemen: Funktionsverbgefüge (zur Verfügung stellen, in Betrieb nehmen), Partizipialattribute (der entwickelte Prozess, die steigenden Kosten) und komplexe Nominalphrasen (die Analyse des neu entwickelten Verfahrens).', '[{"rule":"Funktionsverbgefüge: feste Verbindung Nomen + Verb, formell und präzise.","note":"in Betrieb nehmen, zur Verfügung stellen, in Kraft treten"},{"rule":"Partizipialattribute: Partizip I/II + Adjektivendung vor dem Nomen.","note":"der entwickelte (PPII) Prozess, die steigenden (PPI) Kosten"},{"rule":"Komplexe Nominalphrasen: Kern + Erweiterungen (Attribute).","note":"Die detaillierte Analyse des neu entwickelten Verfahrens"},{"rule":"Genitivattribute und Präpositionalattribute als Erweiterung.","note":"die Optimierung des Verfahrens, die Abhängigkeit von Rohstoffen"}]', '[{"german":"Die neu in Betrieb genommene Produktionsanlage läuft stabil.","arabic":"منشأة الإنتاج التي تم تشغيلها حديثاً تعمل بثبات.","english":"The newly commissioned production plant is running stably."},{"german":"Die Implementierung der optimierten Prozesse ist abgeschlossen.","arabic":"تم الانتهاء من تنفيذ العمليات المحسنة.","english":"The implementation of the optimized processes is complete."},{"german":"Das von der Regierung verabschiedete Gesetz tritt in Kraft.","arabic":"القانون الذي أقرته الحكومة يدخل حيز التنفيذ.","english":"The law passed by the government comes into force."}]', '[{"mistake":"Die Anlage wird in Betrieb genommen. / Die Anlage ist in Betrieb gestellt.","correction":"Korrekt: \"in Betrieb nehmen\" (Inbetriebnahme) oder \"in Betrieb setzen\".","explanation":"Die Präposition \"in\" in Funktionsverbgefügen ist oft fest und nicht austauschbar."},{"mistake":"Der entwickelnde Prozess ist effizient.","correction":"Der entwickelte Prozess ist effizient. (wenn abgeschlossen)","explanation":"Partizip I = gleichzeitig/aktiv, Partizip II = abgeschlossen/passiv."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Die Software wurde in _____ genommen. (Betrieb)', '["Betrieb","der Betrieb","die Betrieb","Betrieben"]', 'Betrieb', 'In Betrieb nehmen = Funktionsverbgefüge.', 1, 1),
  (l_id, 'multiple_choice', 'Welche Struktur ist ein Partizipialattribut?', '["der entwickelte Prozess","der Prozess wird entwickelt","weil der Prozess entwickelt wurde","den Prozess entwickeln"]', 'der entwickelte Prozess', 'Partizip II + Adjektivendung + Nomen.', 1, 2),
  (l_id, 'translation', 'Übersetze: "The analysis of the newly developed process."', '["Die Analyse des neu entwickelten Prozesses.","Die Analyse des entwickelten neuen Prozesses.","Die neue Analyse des entwickelten Prozesses.","Neu die Analyse des entwickelten Prozesses."]', 'Die Analyse des neu entwickelten Prozesses.', 'Komplexe Nominalphrase mit Genitiv und Partizipialattribut.', 1, 3),
  (l_id, 'fill_gap', 'Die _____ (steigen) Produktionskosten sind ein Problem.', '["steigenden","gestiegenen","steigende","gestiegene"]', 'steigenden', 'Partizip I (steigend) + en (Plural, bestimmter Artikel).', 1, 4),
  (l_id, 'multiple_choice', 'Was ist typisch für Funktionsverbgefüge?', '["Das Verb trägt die Hauptbedeutung","Das Nomen trägt die Hauptbedeutung","Die Präposition ist frei wählbar","Die Wendung ist informell"]', 'Das Nomen trägt die Hauptbedeutung', 'Beim Funktionsverbgefüge trägt das Nomen die Bedeutung, das Verb ist grammatikalisch.', 1, 5);
