  (l_id, 'translation', 'Übersetze: "The newly developed and certified facility."', '["Die neu entwickelte und zertifizierte Anlage.","Die neue entwickelte zertifizierte Anlage.","Die Anlage neu entwickelt und zertifiziert.","Neu die entwickelte zertifizierte Anlage."]', 'Die neu entwickelte und zertifizierte Anlage.', 'Adverb + Partizip + Partizip + Nomen.', 1, 3),
  (l_id, 'multiple_choice', 'Was kennzeichnet ein Funktionsverbgefüge?', '["Verb ist Hauptbedeutung","Nomen ist Hauptbedeutung","Keine Präposition","Informelle Sprache"]', 'Nomen ist Hauptbedeutung', 'Das Nomen trägt die Hauptbedeutung, das Verb ist grammatikalisch.', 1, 4),
