  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Indirekte Rede – Konjunktiv I (alle Formen)', 'Die indirekte Rede gibt eine Äußerung einer anderen Person wieder, ohne sie wörtlich zu zitieren. Im Deutschen verwenden wir dafür den Konjunktiv I. Die Formen: er habe, sie sei, sie hätten. Im Präsens wird das -e-n des Verbs durch -e (3. Pers.) oder andere Endungen ersetzt.', '[{"rule":"Bildung Konjunktiv I Präsens: Verbstamm + -e, -est, -e, -en, -et, -en.","note":"er habe, sie sei, sie hätten, er werde"},{"rule":"3. Person Singular ist die wichtigste Form (Unterschied zum Indikativ).","note":"er habe (Indikativ: er hat), sie sei (Indikativ: sie ist)"},{"rule":"Konjunktiv I Vergangenheit: sei/wäre/habe/hätte + Partizip Perfekt.","note":"er habe gesagt, sie sei gekommen"},{"rule":"Konjunktiv I Futur: werde + Infinitiv oder würde + Infinitiv.","note":"er werde kommen, sie würde gehen"},{"rule":"Wenn Konjunktiv I = Indikativ (1. Pers.), verwendet man Konjunktiv II als Ersatz.","note":"Sie sagten, sie hätten (statt: sie haben) Zeit."}]', '[{"german":"Er sagt, er habe keine Zeit.","arabic":"يقول إنه ليس لديه وقت.","english":"He says he has no time."},{"german":"Sie behauptet, sie sei unschuldig.","arabic":"تدعي أنها بريئة.","english":"She claims she is innocent."},{"german":"Der Minister erklärte, die Reform sei notwendig.","arabic":"أوضح الوزير أن الإصلاح ضروري.","english":"The minister explained that the reform was necessary."},{"german":"Die Bürger fordern, dass die Regierung handle.","arabic":"يطالب المواطنون بأن تتحرك الحكومة.","english":"The citizens demand that the government act."},{"german":"Sie fragten, ob er kommen werde.","arabic":"سألوا إذا كان سيأتي.","english":"They asked if he would come."}]', '[{"mistake":"Er sagt, er hat keine Zeit. (Indikativ)","correction":"Er sagt, er habe keine Zeit. (Konjunktiv I)","explanation":"In der indirekten Rede verwendet man Konjunktiv I, nicht Indikativ."},{"mistake":"Sie sagte, sie sei gekommen. Korrekt, aber: sie seien (Plural).","correction":"Sie sagten, sie seien gekommen.","explanation":"Plural von \"sie sei\" ist \"sie seien\"."},{"mistake":"Er fragt, ob ich komme. (Indikativ statt Konjunktiv)","correction":"Er fragt, ob ich komme. (Indikativ ist bei \"ob\" akzeptabel, Konjunktiv: Er fragt, ob ich komme/kommen werde.)","explanation":"Bei indirekten Fragen mit \"ob\" ist der Indikativ üblich, Konjunktiv I möglich."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Er sagt, er _____ keine Zeit. (haben - Konjunktiv I)', '["habe","hat","hätte","habt"]', 'habe', '3. Person Singular Konjunktiv I von "haben": er habe.', 1, 1),
  (l_id, 'multiple_choice', 'Wie bildet man die indirekte Rede?', '["Mit Indikativ","Mit Konjunktiv I","Mit Konjunktiv II","Mit Partizip"]', 'Mit Konjunktiv I', 'Die indirekte Rede verwendet den Konjunktiv I.', 1, 2),
  (l_id, 'translation', 'Übersetze: "He says he is innocent."', '["Er sagt, er ist unschuldig.","Er sagt, er sei unschuldig.","Er sagt, er wäre unschuldig.","Er sagt, er wird unschuldig."]', 'Er sagt, er sei unschuldig.', 'Konjunktiv I von "sein": er sei.', 1, 3),
  (l_id, 'fill_gap', 'Sie sagten, sie _____ gekommen. (sein - Konjunktiv I)', '["seien","sind","wären","waren"]', 'seien', '3. Person Plural Konjunktiv I von "sein": sie seien.', 1, 4),
  (l_id, 'multiple_choice', 'Wann verwendet man Konjunktiv II als Ersatz für Konjunktiv I?', '["Wenn Konjunktiv I = Indikativ","Immer","Nie","Nur in der Vergangenheit"]', 'Wenn Konjunktiv I = Indikativ', 'Wenn Konjunktiv I mit dem Indikativ identisch ist, verwendet man Konjunktiv II als Ersatzform.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Integration"?', '["الاندماج","التنوع","الاستدامة","التماسك"]', 'الاندماج', 1, 1),
  (l_id, 'true_false', 'Die indirekte Rede verwendet Konjunktiv I.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Er sagt, er _____ (haben - KI) keine Zeit.', '["habe","hat","hätte","habt"]', 'habe', 1, 3),
  (l_id, 'multiple_choice', '"Sie sagt, sie sei krank" bedeutet:', '["قالت إنها مريضة","هي مريضة","ستمرض","كانت مريضة"]', 'قالت إنها مريضة', 1, 4),
  (l_id, 'true_false', 'Konjunktiv I von "sein" (3.Pers.Sg) ist "sei".', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'multiple_choice', 'Welche Konjunktion leitet oft die indirekte Rede ein?', '["dass","weil","obwohl","wenn"]', 'dass', 1, 6);
