  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'das Oktoberfest', 'مهرجان أكتوبر', 'Oktoberfest', 'das', NULL, 'noun', 'Das Oktoberfest in München ist das größte Volksfest der Welt.', 'The Oktoberfest in Munich is the largest folk festival in the world.', 1),
  (l_id, 'der Karneval', 'الكرنفال', 'carnival', 'der', 'die Karnevale', 'noun', 'In Köln wird Karneval besonders ausgelassen gefeiert.', 'In Cologne, carnival is celebrated particularly exuberantly.', 2),
  (l_id, 'die Wiedervereinigung', 'إعادة التوحيد', 'reunification', 'die', NULL, 'noun', 'Die deutsche Wiedervereinigung war 1990.', 'German reunification was in 1990.', 3),
  (l_id, 'das Denkmal', 'النصب التذكاري', 'monument/memorial', 'das', 'die Denkmäler', 'noun', 'Das Brandenburger Tor ist ein bekanntes Denkmal.', 'The Brandenburg Gate is a famous monument.', 4),
  (l_id, 'die Tradition', 'التقليد', 'tradition', 'die', 'die Traditionen', 'noun', 'Die Tradition des Weihnachtsmarktes ist in Deutschland sehr alt.', 'The tradition of the Christmas market is very old in Germany.', 5),
  (l_id, 'das Kulturerbe', 'التراث الثقافي', 'cultural heritage', 'das', NULL, 'noun', 'Das UNESCO-Weltkulturerbe umfasst viele deutsche Stätten.', 'The UNESCO World Heritage includes many German sites.', 6);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Indirekte Rede – Konjunktiv I in Zeitungsberichten', 'In Zeitungsberichten und Nachrichten wird die indirekte Rede verwendet, um Aussagen von Politikern, Experten und anderen Personen wiederzugeben. Der Konjunktiv I signalisiert, dass der Journalist die Aussage nicht selbst übernimmt, sondern neutral wiedergibt.', '[{"rule":"Konjunktiv I Präsens: Verbstamm + spezifische Endungen.","note":"er habe (haben), sie sei (sein), er werde (werden), er könne (können)"},{"rule":"Konjunktiv I Perfekt: habe/sei + Partizip Perfekt.","note":"er habe gesagt, sie sei gekommen"},{"rule":"Konjunktiv I Futur: werde + Infinitiv.","note":"er werde kommen"},{"rule":"Bericht über Aussagen in der Vergangenheit: Konjunktiv I bleibt im Präsens.","note":"Er sagte gestern, er komme morgen. (nicht: kam)"},{"rule":"Bei Identität mit Indikativ -> Konjunktiv II als Ersatz.","note":"Sie sagten, sie hätten (statt haben) Zeit."}]', '[{"german":"Der Bundeskanzler erklärte, die Reform sei dringend notwendig.","arabic":"أوضح المستشار أن الإصلاح ضروري بشكل عاجل.","english":"The Chancellor stated that the reform was urgently necessary."},{"german":"Die Opposition behauptet, die Regierung handle zu langsam.","arabic":"تدعي المعارضة أن الحكومة تتصرف ببطء شديد.","english":"The opposition claims that the government is acting too slowly."},{"german":"Die Studie zeige, dass der Klimawandel schneller voranschreite als erwartet.","arabic":"تشير الدراسة إلى أن تغير المناخ يتقدم بشكل أسرع من المتوقع.","english":"The study showed that climate change is progressing faster than expected."},{"german":"Der Experte sagte, die Wirtschaft werde sich im nächsten Jahr erholen.","arabic":"قال الخبير إن الاقتصاد سوف يتعافى في العام المقبل.","english":"The expert said the economy would recover next year."},{"german":"Die Bürger fordern, dass die Politiker mehr für den Klimaschutz täten.","arabic":"يطالب المواطنون بأن يفعل السياسيون المزيد لحماية المناخ.","english":"Citizens demand that politicians do more for climate protection."}]', '[{"mistake":"Der Kanzler sagte, die Reform ist notwendig.","correction":"Der Kanzler sagte, die Reform sei notwendig.","explanation":"In der indirekten Rede muss Konjunktiv I (sei) stehen, nicht Indikativ (ist)."},{"mistake":"Die Studie zeigte, dass der Klimawandel schneller voranschreitet.","correction":"Die Studie zeigte, dass der Klimawandel schneller voranschreite.","explanation":"Gleichzeitigkeit in der Vergangenheit: Konjunktiv I Präsens (voranschreite)."},{"mistake":"Sie fragten, ob er werde kommen.","correction":"Sie fragten, ob er kommen werde.","explanation":"In Nebensätzen steht \"werde\" am Ende: \"ob er kommen werde\"."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Der Kanzler sagte, die Reform _____ notwendig. (sein - KI)', '["sei","ist","wäre","war"]', 'sei', 'Konjunktiv I von "sein": er/sie sei.', 1, 1),
  (l_id, 'multiple_choice', 'Welche Funktion hat der Konjunktiv I in Zeitungsberichten?', '["Die Meinung des Journalisten","Neutrale Wiedergabe einer Aussage","Eine Frage","Einen Befehl"]', 'Neutrale Wiedergabe einer Aussage', 'Konjunktiv I signalisiert neutrale Distanz zur wiedergegebenen Aussage.', 1, 2),
  (l_id, 'translation', 'Übersetze: "The expert said the economy will recover."', '["Der Experte sagte, die Wirtschaft erhole sich.","Der Experte sagte, die Wirtschaft erholt sich.","Der Experte sagte, die Wirtschaft erholte sich.","Der Experte sagte, die Wirtschaft habe sich erholt."]', 'Der Experte sagte, die Wirtschaft erhole sich.', 'Konjunktiv I Präsens von "sich erholen": erhole sich.', 1, 3),
  (l_id, 'fill_gap', 'Die Opposition behauptet, die Regierung _____ zu langsam. (handeln - KI)', '["handle","handelt","handelte","würde handeln"]', 'handle', 'Konjunktiv I von "handeln": er/sie handle.', 1, 4),
  (l_id, 'multiple_choice', 'Welcher Satz ist korrekt in der indirekten Rede?', '["Er sagt, er hat keine Zeit.","Er sagt, er habe keine Zeit.","Er sagt, er hätte keine Zeit gehabt.","Er sagt, er hatte keine Zeit."]', 'Er sagt, er habe keine Zeit.', 'Präsens Konjunktiv I: er habe.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Wiedervereinigung"?', '["إعادة التوحيد","الاندماج","التنوع","الاستدامة"]', 'إعادة التوحيد', 1, 1),
  (l_id, 'true_false', 'In der indirekten Rede verwendet man Konjunktiv I.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Sie sagt, sie _____ krank. (sein - KI)', '["sei","ist","wäre","war"]', 'sei', 1, 3),
  (l_id, 'multiple_choice', '"Der Minister erklärte, die Reform sei notwendig." Das bedeutet:', '["أوضح الوزير أن الإصلاح ضروري","الوزير يعتقد أن الإصلاح ضروري","الإصلاح ليس ضرورياً","الوزير يرفض الإصلاح"]', 'أوضح الوزير أن الإصلاح ضروري', 1, 4),
  (l_id, 'true_false', 'Konjunktiv I von "haben" (3.Pers.Sg) ist "habe".', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'multiple_choice', 'Was ist die Ersatzform für den Konjunktiv I?', '["Indikativ","Konjunktiv II","Infinitiv","Partizip"]', 'Konjunktiv II', 1, 6);
