  (l_id, 'der Abschluss', 'الاختتام/الإتمام', 'conclusion/completion', 'der', 'die Abschlüsse', 'noun', 'Das Projekt fand einen erfolgreichen Abschluss.', 'The project reached a successful conclusion.', 1),
  (l_id, 'die Entscheidung', 'القرار', 'decision', 'die', 'die Entscheidungen', 'noun', 'Die Regierung traf eine wichtige Entscheidung.', 'The government made an important decision.', 2),
  (l_id, 'die Verantwortung', 'المسؤولية', 'responsibility', 'die', 'die Verantwortungen', 'noun', 'Der Minister übernahm die Verantwortung.', 'The minister took responsibility.', 3),
  (l_id, 'der Einfluss', 'التأثير', 'influence', 'der', 'die Einflüsse', 'noun', 'Die Medien haben großen Einfluss auf die öffentliche Meinung.', 'The media have great influence on public opinion.', 4),
  (l_id, 'der Beschluss', 'القرار/الحكم', 'resolution/decision', 'der', 'die Beschlüsse', 'noun', 'Der Bundestag fasste einen Beschluss.', 'The Bundestag passed a resolution.', 5);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Nomen-Verb-Verbindungen und Verbalstil vs. Nominalstil', 'Nomen-Verb-Verbindungen (auch: Streckformen) sind feste Verbindungen wie "eine Entscheidung treffen" (statt "entscheiden") oder "Abschluss finden" (statt "abschließen"). Der Nominalstil verwendet viele Nomen, der Verbalstil mehr Verben. Der Nominalstil ist formeller, der Verbalstil lebendiger.', '[{"rule":"Nomen-Verb-Verbindung: Funktionsverb + Nomen (Akkusativ oder präpositional).","note":"eine Entscheidung treffen, Abschluss finden, Einfluss nehmen"},{"rule":"Typische Verben: treffen, finden, nehmen, stellen, bringen, kommen.","note":"Maßnahmen ergreifen, in Gang setzen, zur Sprache bringen"},{"rule":"Nominalstil: viele Nomen, abstrakter, formeller.","note":"Die Entscheidung des Gremiums fand allgemeine Zustimmung."},{"rule":"Verbalstil: mehr Verben, konkreter, lebendiger.","note":"Das Gremium entschied, und alle stimmten zu."},{"rule":"Im B2 sollte man beide Stile kennen und situationsgerecht einsetzen.","note":"Präsentationen: Nominalstil, Gespräche: Verbalstil"}]', '[{"german":"Die Regierung traf eine wichtige Entscheidung.","arabic":"اتخذت الحكومة قراراً مهماً.","english":"The government made an important decision."},{"german":"Das Projekt fand einen erfolgreichen Abschluss.","arabic":"اختتم المشروع بنجاح.","english":"The project reached a successful conclusion."},{"german":"Die Medien nehmen großen Einfluss auf die öffentliche Meinung.","arabic":"لوسائل الإعلام تأثير كبير على الرأي العام.","english":"The media have great influence on public opinion."},{"german":"Verbalstil: Die Regierung entschied schnell.","arabic":"قررت الحكومة بسرعة.","english":"The government decided quickly."},{"german":"Nominalstil: Die Entscheidung der Regierung erfolgte schnell.","arabic":"تم قرار الحكومة بسرعة.","english":"The decision of the government was made quickly."}]', '[{"mistake":"Ich treffe eine Entscheidung. (richtig) / Ich mache eine Entscheidung.","correction":"Ich treffe eine Entscheidung.","explanation":"Es heißt \"eine Entscheidung treffen\", nicht \"machen\"."},{"mistake":"Das Projekt findet Abschluss. (ohne Artikel)","correction":"Das Projekt findet einen Abschluss / findet seinen Abschluss.","explanation":"Nomen-Verb-Verbindung: \"einen/seinen Abschluss finden\"."},{"mistake":"Er nahm Einfluss auf die Entscheidung. (falsche Präposition)","correction":"Er nahm Einfluss auf die Entscheidung. (Einfluss nehmen AUF + Akk)","explanation":"\"Einfluss nehmen\" + auf + Akkusativ."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Die Regierung _____ eine Entscheidung. (treffen)', '["traf","machte","gab","nahm"]', 'traf', 'Eine Entscheidung treffen = to make a decision.', 1, 1),
  (l_id, 'multiple_choice', 'Welcher Satz ist im Nominalstil?', '["Die Regierung entschied schnell.","Die Entscheidung der Regierung erfolgte schnell.","Die Regierung hat schnell entschieden.","Die Regierung wird schnell entscheiden."]', 'Die Entscheidung der Regierung erfolgte schnell.', 'Nominalstil: "Die Entscheidung ... erfolgte" statt "entschied".', 1, 2),
  (l_id, 'translation', 'Übersetze die Nomen-Verb-Verbindung: "to take responsibility."', '["Entscheidung treffen","Verantwortung übernehmen","Einfluss nehmen","Abschluss finden"]', 'Verantwortung übernehmen', 'Die Verantwortung übernehmen = to take responsibility.', 1, 3),
  (l_id, 'fill_gap', 'Der Bundestag _____ einen Beschluss. (fassen)', '["fasste","machte","gab","stellte"]', 'fasste', 'Einen Beschluss fassen = to pass a resolution.', 1, 4),
  (l_id, 'multiple_choice', 'Welcher Stil ist formeller?', '["Verbalstil","Nominalstil","Beide gleich","Weder noch"]', 'Nominalstil', 'Der Nominalstil mit vielen Nomen ist formeller und abstrakter.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Entscheidung treffen"?', '["اتخاذ قرار","اتخاذ إجراء","تحمل مسؤولية","ممارسة تأثير"]', 'اتخاذ قرار', 1, 1),
  (l_id, 'true_false', 'Nominalstil ist formeller als Verbalstil.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Die Medien _____ Einfluss auf die öffentliche Meinung. (nehmen)', '["nehmen","machen","geben","stellen"]', 'nehmen', 1, 3),
  (l_id, 'multiple_choice', 'Was ist ein Beispiel für eine Nomen-Verb-Verbindung?', '["schnell laufen","eine Entscheidung treffen","gut essen","viel trinken"]', 'eine Entscheidung treffen', 1, 4),
  (l_id, 'true_false', '"Entscheidung treffen" ist dasselbe wie "entscheiden".', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'multiple_choice', 'Welche Präposition passt? "Einfluss nehmen _____ (Akkusativ)".', '["auf","für","gegen","von"]', 'auf', 1, 6);
