  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Berichterstattung', 'التغطية الإخبارية', 'reporting/coverage', 'die', 'die Berichterstattungen', 'noun', 'Die Berichterstattung über das Ereignis war umfassend.', 'The coverage of the event was comprehensive.', 1),
  (l_id, 'die Quelle', 'المصدر', 'source', 'die', 'die Quellen', 'noun', 'Die Quelle der Information ist vertrauenswürdig.', 'The source of the information is trustworthy.', 2),
  (l_id, 'die Stellungnahme', 'بيان/تصريح', 'statement', 'die', 'die Stellungnahmen', 'noun', 'Die Regierung gab eine Stellungnahme ab.', 'The government issued a statement.', 3),
  (l_id, 'der Kommentar', 'التعليق', 'commentary', 'der', 'die Kommentare', 'noun', 'Der Kommentar in der Zeitung war kritisch.', 'The commentary in the newspaper was critical.', 4),
  (l_id, 'die Analyse', 'التحليل', 'analysis', 'die', 'die Analysen', 'noun', 'Die Analyse der politischen Lage war differenziert.', 'The analysis of the political situation was differentiated.', 5);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Indirekte Rede und Nomen-Verb-Verbindungen in Nachrichten', 'In Nachrichten und Zeitungsberichten treten indirekte Rede (Konjunktiv I) und Nomen-Verb-Verbindungen häufig gemeinsam auf. Die indirekte Rede gibt Aussagen neutral wieder, Nomen-Verb-Verbindungen machen den Text formell und präzise.', '[{"rule":"Indirekte Rede in Nachrichten: Konjunktiv I für Distanz und Neutralität.","note":"Der Präsident erklärte, die Lage sei stabil."},{"rule":"Nomen-Verb-Verbindungen im Nominalstil: Entscheidung treffen, Beschluss fassen.","note":"Das Parlament fasste den Beschluss, die Reform durchzuführen."},{"rule":"Kombination: indirekte Rede + Nomen-Verb-Verbindung.","note":"Der Minister gab bekannt, dass die Regierung eine Entscheidung getroffen habe."},{"rule":"Häufig in der politischen Berichterstattung.","note":"Die Opposition teilte mit, sie nehme Stellung zu dem Gesetzesentwurf."}]', '[{"german":"Der Präsident erklärte, die Regierung habe eine Entscheidung getroffen.","arabic":"أعلن الرئيس أن الحكومة اتخذت قراراً.","english":"The president stated that the government had made a decision."},{"german":"Die Opposition teilte mit, sie nehme Stellung zu dem Gesetz.","arabic":"أعلنت المعارضة أنها ستدلي ببيان بشأن القانون.","english":"The opposition announced that it would comment on the law."},{"german":"Der Bericht zeige, dass die Maßnahmen Wirkung gezeigt hätten.","arabic":"يظهر التقرير أن الإجراءات قد أظهرت تأثيراً.","english":"The report showed that the measures had had an effect."},{"german":"Die Bürger fordern, die Politik müsse Verantwortung übernehmen.","arabic":"يطالب المواطنون بأن تتحمل السياسة المسؤولية.","english":"Citizens demand that politics must take responsibility."}]', '[{"mistake":"Der Präsident erklärte, die Regierung hat eine Entscheidung getroffen.","correction":"Der Präsident erklärte, die Regierung habe eine Entscheidung getroffen.","explanation":"Indirekte Rede braucht Konjunktiv I (habe), nicht Indikativ (hat)."},{"mistake":"Die Opposition sagte, sie nimmt Stellung.","correction":"Die Opposition sagte, sie nehme Stellung.","explanation":"Stellung nehmen + Konjunktiv I: sie nehme Stellung."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Der Präsident erklärte, die Regierung _____ eine Entscheidung getroffen. (haben - KI)', '["habe","hat","hätte","hatte"]', 'habe', 'Konjunktiv I Perfekt: habe ... getroffen.', 1, 1),
  (l_id, 'multiple_choice', 'Warum verwendet man Konjunktiv I in Nachrichten?', '["Um zu betonen","Für neutrale Distanz","Um zu fragen","Um zu befehlen"]', 'Für neutrale Distanz', 'Konjunktiv I signalisiert, dass der Journalist die Aussage neutral wiedergibt.', 1, 2),
  (l_id, 'translation', 'Übersetze: "The minister announced that the cabinet had made a decision."', '["Der Minister gab bekannt, das Kabinett habe eine Entscheidung getroffen.","Der Minister sagt, das Kabinett hat eine Entscheidung getroffen.","Der Minister gab bekannt, das Kabinett hat entschieden.","Der Minister sagt, das Kabinett hätte entschieden."]', 'Der Minister gab bekannt, das Kabinett habe eine Entscheidung getroffen.', 'Indirekte Rede (Konjunktiv I) + Nomen-Verb-Verbindung.', 1, 3),
  (l_id, 'fill_gap', 'Die Bürger fordern, die Politik müsse _____ übernehmen. (die Verantwortung)', '["Verantwortung","die Verantwortung","Verantwortungen","eine Verantwortung"]', 'Verantwortung', 'Verantwortung übernehmen = Nomen-Verb-Verbindung.', 1, 4),
  (l_id, 'multiple_choice', 'Welcher Satz enthält eine Nomen-Verb-Verbindung?', '["Der Minister entschied schnell.","Die Regierung traf eine Entscheidung.","Das Parlament diskutierte lange.","Die Bürger wählten einen Kandidaten."]', 'Die Regierung traf eine Entscheidung.', '"Eine Entscheidung treffen" = Nomen-Verb-Verbindung.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Stellungnahme"?', '["بيان/تصريح","التعليق","التحليل","المصدر"]', 'بيان/تصريح', 1, 1),
  (l_id, 'true_false', 'Konjunktiv I in Nachrichten signalisiert Neutralität.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Der Minister gab bekannt, das Kabinett _____ (haben - KI) entschieden.', '["habe","hat","hätte","hatte"]', 'habe', 1, 3),
  (l_id, 'multiple_choice', '"Eine Entscheidung treffen" bedeutet:', '["اتخاذ قرار","اتخاذ إجراء","بدء المشروع","إنهاء العمل"]', 'اتخاذ قرار', 1, 4),
  (l_id, 'true_false', 'Nominalstil ist lebendiger als Verbalstil.', '["Richtig","Falsch"]', 'Falsch', 1, 5),
  (l_id, 'multiple_choice', 'Welche Verbindung passt? "Die Opposition ___ zur Reform."', '["nahm Stellung","traf Entscheidung","fand Abschluss","fasste Beschluss"]', 'nahm Stellung', 1, 6);
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Demokratie', 'الديمقراطية', 'democracy', 'die', 'die Demokratien', 'noun', 'Die Demokratie lebt von der Beteiligung der Bürger.', 'Democracy thrives on citizen participation.', 1),
  (l_id, 'die Teilhabe', 'المشاركة', 'participation', 'die', NULL, 'noun', 'Die Teilhabe an der Gesellschaft ist ein Grundrecht.', 'Participation in society is a fundamental right.', 2),
  (l_id, 'die Toleranz', 'التسامح', 'tolerance', 'die', NULL, 'noun', 'Toleranz ist eine Grundlage des Zusammenlebens.', 'Tolerance is a foundation of coexistence.', 3),
  (l_id, 'der Respekt', 'الاحترام', 'respect', 'der', NULL, 'noun', 'Respekt vor anderen Kulturen ist wichtig.', 'Respect for other cultures is important.', 4),
  (l_id, 'die Freiheit', 'الحرية', 'freedom', 'die', 'die Freiheiten', 'noun', 'Die Pressefreiheit ist in Deutschland verfassungsrechtlich geschützt.', 'Freedom of the press is constitutionally protected in Germany.', 5);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Wiederholung: Indirekte Rede, Nomen-Verb-Verbindungen, Verbal-/Nominalstil', 'In dieser Wiederholung festigen wir die indirekte Rede mit Konjunktiv I (er habe, sie sei, sie hätten), Nomen-Verb-Verbindungen (Entscheidung treffen, Verantwortung übernehmen) und den Unterschied zwischen Verbal- und Nominalstil.', '[{"rule":"Indirekte Rede: Konjunktiv I (er habe, sie sei, er werde). Ersatzform: Konjunktiv II.","note":"Er sagt, er habe keine Zeit."},{"rule":"Nomen-Verb-Verbindungen: feste Wendungen mit Funktionsverb.","note":"Entscheidung treffen, Verantwortung übernehmen, Abschluss finden"},{"rule":"Verbalstil: aktiv, konkret, lebendig. Nominalstil: abstrakt, formell.","note":"Verb: Sie entschied. Nomen: Die Entscheidung erfolgte."},{"rule":"Wahl des Stils abhängig vom Kontext (formell vs. informell).","note":"Nominalstil für Berichte, Verbalstil für Gespräche."}]', '[{"german":"Der Präsident erklärte, die Demokratie sei stark.","arabic":"أعلن الرئيس أن الديمقراطية قوية.","english":"The president declared that democracy was strong."},{"german":"Die Regierung übernahm die Verantwortung für die Reform.","arabic":"تحملت الحكومة مسؤولية الإصلاح.","english":"The government took responsibility for the reform."},{"german":"Verbalstil: Die Bürger beteiligten sich aktiv.","arabic":"شارك المواطنون بنشاط.","english":"The citizens actively participated."},{"german":"Nominalstil: Die aktive Beteiligung der Bürger war bemerkenswert.","arabic":"كانت المشاركة النشطة للمواطنين ملحوظة.","english":"The active participation of the citizens was remarkable."}]', '[{"mistake":"Sie sagt, sie ist müde. (indirekte Rede falsch)","correction":"Sie sagt, sie sei müde.","explanation":"Indirekte Rede braucht Konjunktiv I: \"sie sei\"."},{"mistake":"Der Minister machte eine Entscheidung.","correction":"Der Minister traf eine Entscheidung.","explanation":"Richtige Nomen-Verb-Verbindung: \"eine Entscheidung treffen\"."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Der Kanzler sagt, die Lage _____ stabil. (sein - KI)', '["sei","ist","wäre","war"]', 'sei', 'Konjunktiv I von "sein": er/sie sei.', 1, 1),
  (l_id, 'multiple_choice', 'Welcher Satz ist im Verbalstil?', '["Die Entscheidung der Regierung erfolgte schnell.","Die Regierung entschied schnell.","Die schnelle Entscheidung der Regierung.","Die Entscheidung fand statt."]', 'Die Regierung entschied schnell.', 'Verbalstil: Verb "entschied" als Kern des Satzes.', 1, 2),
  (l_id, 'translation', 'Übersetze: "She says she is coming tomorrow." (indirekte Rede)', '["Sie sagt, sie kommt morgen.","Sie sagt, sie komme morgen.","Sie sagt, sie käme morgen.","Sie sagt, sie werde morgen kommen."]', 'Sie sagt, sie komme morgen.', 'Konjunktiv I Präsens: sie komme.', 1, 3),
  (l_id, 'fill_gap', 'Die Regierung _____ die Verantwortung. (übernehmen)', '["übernahm","machte","traf","gab"]', 'übernahm', 'Die Verantwortung übernehmen = to take responsibility.', 1, 4),
  (l_id, 'multiple_choice', 'Welche Form ist Konjunktiv I von "haben" (3.Pers.Pl)?', '["haben","hätten","hatten","habet"]', 'haben', 'Konjunktiv I Präsens 3.Pers.Pl = haben (gleich Indikativ, daher oft Ersatzform "hätten").', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Demokratie"?', '["الديمقراطية","الحرية","المشاركة","التسامح"]', 'الديمقراطية', 1, 1),
  (l_id, 'true_false', 'Konjunktiv I wird für die indirekte Rede verwendet.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Sie sagt, sie _____ (sein - KI) krank.', '["sei","ist","wäre","war"]', 'sei', 1, 3),
  (l_id, 'multiple_choice', '"Verantwortung übernehmen" bedeutet:', '["يتحمل المسؤولية","يتخذ قراراً","يؤدي دوراً","يمارس تأثيراً"]', 'يتحمل المسؤولية', 1, 4),
  (l_id, 'true_false', 'Der Nominalstil ist lebendiger als der Verbalstil.', '["Richtig","Falsch"]', 'Falsch', 1, 5),
  (l_id, 'multiple_choice', 'Welche Nomen-Verb-Verbindung ist korrekt?', '["eine Entscheidung treffen","eine Entscheidung machen","einen Entscheidung nehmen","eine Entscheidung geben"]', 'eine Entscheidung treffen', 1, 6);
  insert into public.course_lessons (module_id, title, description, topic, lesson_type, objectives, duration_minutes, order_index, is_published)
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Der Minister sagt, die Reform _____ notwendig. (sein - KI)', '["sei","ist","wäre","war"]', 'sei', 'Konjunktiv I von "sein": sie sei.', 1, 1),
  (l_id, 'multiple_choice', 'Was ist die Funktion des Konjunktiv I in Nachrichten?', '["Sicherheit ausdrücken","Neutrale Distanz","Frage stellen","Befehl geben"]', 'Neutrale Distanz', 'Konjunktiv I signalisiert neutrale Wiedergabe.', 1, 2),
  (l_id, 'translation', 'Übersetze: "The opposition claims that the government is acting too slowly."', '["Die Opposition behauptet, die Regierung handle zu langsam.","Die Opposition sagt, die Regierung handelt zu langsam.","Die Opposition behauptet, die Regierung handelte zu langsam.","Die Opposition sagt, die Regierung würde zu langsam handeln."]', 'Die Opposition behauptet, die Regierung handle zu langsam.', 'Konjunktiv I von "handeln": er handle.', 1, 3),
  (l_id, 'multiple_choice', 'Was ist keine Nomen-Verb-Verbindung?', '["Entscheidung treffen","Verantwortung übernehmen","schnell laufen","Abschluss finden"]', 'schnell laufen', '"Schnell laufen" ist eine normale Verb-Adverb-Kombination, keine feste Nomen-Verb-Verbindung.', 1, 4),
  (l_id, 'fill_gap', 'Die Regierung _____ eine Entscheidung. (treffen - Präteritum)', '["traf","machte","gab","nahm"]', 'traf', 'Eine Entscheidung treffen -> Präteritum: traf.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Toleranz"?', '["التسامح","المشاركة","الحرية","الاحترام"]', 'التسامح', 1, 1),
  (l_id, 'true_false', 'Konjunktiv I von "sein" (3.Pers.Sg) ist "sei".', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Er sagt, er _____ (haben - KI) keine Zeit.', '["habe","hat","hätte","habt"]', 'habe', 1, 3),
  (l_id, 'multiple_choice', 'Welcher Stil ist formeller?', '["Verbalstil","Nominalstil","Keiner","Beide"]', 'Nominalstil', 1, 4),
  (l_id, 'true_false', '"Abschluss finden" ist eine Nomen-Verb-Verbindung.', '["Richtig","Falsch"]', 'Richtig', 1, 5),
  (l_id, 'multiple_choice', 'Was ersetzt den Konjunktiv I, wenn er = Indikativ?', '["Konjunktiv II","Indikativ","Infinitiv","Partizip"]', 'Konjunktiv II', 1, 6),
  (l_id, 'fill_blank', 'Die Medien _____ Einfluss auf die öffentliche Meinung. (nehmen)', '["nehmen","geben","machen","stellen"]', 'nehmen', 1, 7),
  (l_id, 'multiple_choice', '"Die Regierung übernahm die Verantwortung" bedeutet:', '["تحملت الحكومة المسؤولية","اتخذت الحكومة قراراً","أقرت الحكومة قانوناً","رفضت الحكومة المقترح"]', 'تحملت الحكومة المسؤولية', 1, 8);
