  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'der Markt', 'السوق', 'market', 'der', 'die Märkte', 'noun', 'Der deutsche Markt ist für Exporteure sehr attraktiv.', 'The German market is very attractive for exporters.', 1),
  (l_id, 'die Inflation', 'التضخم', 'inflation', 'die', 'die Inflationen', 'noun', 'Die Inflation ist in diesem Jahr gestiegen.', 'Inflation has risen this year.', 2),
  (l_id, 'das Bruttoinlandsprodukt', 'الناتج المحلي الإجمالي', 'gross domestic product (GDP)', 'das', 'die Bruttoinlandsprodukte', 'noun', 'Das Bruttoinlandsprodukt wuchs um 2 Prozent.', 'The gross domestic product grew by 2 percent.', 3),
  (l_id, 'die Steuer', 'الضريبة', 'tax', 'die', 'die Steuern', 'noun', 'Die Steuern in Deutschland sind relativ hoch.', 'Taxes in Germany are relatively high.', 4),
  (l_id, 'die Investition', 'الاستثمار', 'investment', 'die', 'die Investitionen', 'noun', 'Investitionen in erneuerbare Energien nehmen zu.', 'Investments in renewable energies are increasing.', 5),
  (l_id, 'der Zins', 'الفائدة', 'interest rate', 'der', 'die Zinsen', 'noun', 'Die Zinsen sind im Moment sehr niedrig.', 'Interest rates are very low at the moment.', 6);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Modalpartikeln: doch, ja, eben, halt, eigentlich, wohl', 'Modalpartikeln sind kleine Wörter, die die Einstellung des Sprechers zur Aussage ausdrücken. Sie sind typisch für die gesprochene Sprache und schwer zu übersetzen. "Doch" (Widerspruch/Betonung), "ja" (bekannte Tatsache), "eben/halt" (Resignation/Unvermeidlichkeit), "eigentlich" (eigentlich/überrascht), "wohl" (Vermutung).', '[{"rule":"\"doch\" drückt Widerspruch oder Betonung aus.","note":"Das ist doch nicht wahr! / Komm doch mit!"},{"rule":"\"ja\" verweist auf eine bekannte Tatsache.","note":"Das ist ja interessant! / Du weißt ja, dass ich Recht habe."},{"rule":"\"eben/halt\" drückt Resignation oder Unvermeidlichkeit aus.","note":"Das ist eben so. / Dann müssen wir halt warten."},{"rule":"\"eigentlich\" drückt eine überraschte Erkenntnis oder eine Korrektur aus.","note":"Das ist eigentlich gar nicht so schwer."},{"rule":"\"wohl\" drückt eine Vermutung oder wahrscheinliche Annahme aus.","note":"Er wird wohl kommen. / Das ist wohl wahr."}]', '[{"german":"Das ist doch unglaublich, was die Regierung beschlossen hat!","arabic":"هذا لا يصدق، ما قررته الحكومة!","english":"That is really unbelievable, what the government has decided!"},{"german":"Die Inflation ist ja bekanntlich ein großes Problem.","arabic":"من المعروف بالطبع أن التضخم مشكلة كبيرة.","english":"Inflation is, as we know, a big problem."},{"german":"Die Zinsen sind eben niedrig, daran können wir nichts ändern.","arabic":"الفائدة منخفضة ببساطة، لا يمكننا تغيير ذلك.","english":"Interest rates are just low, we cannot change that."},{"german":"Das ist eigentlich eine gute Idee für die Wirtschaft.","arabic":"هذه في الحقيقة فكرة جيدة للاقتصاد.","english":"That is actually a good idea for the economy."},{"german":"Die Wirtschaft wird sich wohl im nächsten Jahr erholen.","arabic":"من المحتمل أن يتعافى الاقتصاد في العام القادم.","english":"The economy will probably recover next year."}]', '[{"mistake":"Das ist ja interessant! (höflich) / Das ist ja nicht interessant!","correction":"Modalpartikeln können nicht verneint werden: \"Das ist ja nicht interessant\" ist falsch.","explanation":"Modalpartikeln können nicht mit \"nicht\" kombiniert werden."},{"mistake":"Ich habe eigentlich kein Geld. (eigentlich = actually) / Ich komme eigentlich nicht. (falsch)","correction":"Ich komme wohl nicht. / Ich komme eigentlich schon, aber ...","explanation":"\"Eigentlich\" drückt eine überraschte Erkenntnis oder Korrektur aus, nicht \"probably\"."},{"mistake":"Das ist halt so. (akzeptabel) / Das ist halt nicht so einfach. (falsche Wortstellung)","correction":"Das ist halt nicht so einfach. (nach \"ist\") / Halt ist das so. (falsch)","explanation":"Modalpartikeln stehen meist nach dem Verb, nicht am Satzanfang."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Das ist _____ unglaublich! (Widerspruch/Betonung)', '["doch","ja","eben","wohl"]', 'doch', '"Doch" drückt Betonung oder Widerspruch aus.', 1, 1),
  (l_id, 'multiple_choice', 'Welche Modalpartikel drückt eine bekannte Tatsache aus?', '["doch","ja","halt","wohl"]', 'ja', '"Ja" verweist auf etwas Bekanntes: "Das ist ja bekanntlich ..."', 1, 2),
  (l_id, 'translation', 'Übersetze: "That is actually not so difficult."', '["Das ist eigentlich nicht so schwer.","Das ist doch nicht so schwer.","Das ist ja nicht so schwer.","Das ist wohl nicht so schwer."]', 'Das ist eigentlich nicht so schwer.', '"Eigentlich" drückt eine überraschte Erkenntnis aus.', 1, 3),
  (l_id, 'fill_gap', 'Die Zinsen sind _____, daran können wir nichts ändern. (Resignation)', '["eben","doch","ja","eigentlich"]', 'eben', '"Eben" drückt Resignation oder Unvermeidlichkeit aus.', 1, 4),
  (l_id, 'multiple_choice', 'Welche Partikel drückt eine Vermutung aus?', '["doch","wohl","halt","eigentlich"]', 'wohl', '"Wohl" drückt eine wahrscheinliche Annahme aus.', 1, 5);
