  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Cleft-Sätze: Es ist...der/die/das', 'Cleft-Sätze (Spaltsätze) betonen ein bestimmtes Satzelement. Die Struktur ist: "Es ist + betontes Element + Relativsatz". "Es ist die Regierung, die die Entscheidung trifft." Dadurch wird ein Satzteil hervorgehoben. Im Deutschen typisch für formelle und politische Rede.', '[{"rule":"Cleft-Satz: Es ist + Nomen/Gruppe + Relativpronomen (der/die/das).","note":"Es ist die Regierung, die die Entscheidung trifft."},{"rule":"Das Relativpronomen richtet sich nach Genus des betonten Nomens.","note":"Es ist der Minister, der ... / Es ist die Partei, die ... / Es ist das Gesetz, das ..."},{"rule":"Der Cleft-Satz kann auch mit \"was\" (für Sachen) oder \"wo\" (für Orte) gebildet werden.","note":"Es ist die Wirtschaft, was zählt. / Es ist in Berlin, wo die Entscheidung fällt."},{"rule":"Die Betonung liegt auf dem Element zwischen \"Es ist\" und dem Relativsatz.","note":"Es ist DIE REGIERUNG, die handelt. (nicht die Opposition)"},{"rule":"Cleft-Sätze sind typisch für Diskussionen und politische Analysen.","note":"Es ist die Steuerpolitik, die die Wirtschaft beeinflusst."}]', '[{"german":"Es ist die Regierung, die für die Wirtschaftspolitik verantwortlich ist.","arabic":"إن الحكومة هي المسؤولة عن سياسة الاقتصاد.","english":"It is the government that is responsible for economic policy."},{"german":"Es ist der Bundestag, der die Gesetze verabschiedet.","arabic":"إن البوندستاغ هو الذي يقر القوانين.","english":"It is the Bundestag that passes the laws."},{"german":"Es ist die Inflation, die die Verbraucher belastet.","arabic":"إن التضخم هو الذي يثقل كاهل المستهلكين.","english":"It is inflation that burdens consumers."},{"german":"Es war die Koalition, die sich auf die Reform geeinigt hat.","arabic":"إن الائتلاف هو الذي اتفق على الإصلاح.","english":"It was the coalition that agreed on the reform."},{"german":"Es sind die Wähler, die über die Zukunft entscheiden.","arabic":"إن الناخبين هم الذين يقررون المستقبل.","english":"It is the voters who decide the future."}]', '[{"mistake":"Es ist die Regierung, wer die Entscheidung trifft.","correction":"Es ist die Regierung, die die Entscheidung trifft.","explanation":"Das Relativpronomen ist \"die\" (feminin), nicht \"wer\"."},{"mistake":"Es ist der Minister, welcher das Gesetz vorschlägt.","correction":"Es ist der Minister, der das Gesetz vorschlägt.","explanation":"Im Deutschen ist \"der\" das übliche Relativpronomen, nicht \"welcher\"."},{"mistake":"Es ist das Parlament, wo die Gesetze gemacht werden.","correction":"Es ist das Parlament, das die Gesetze macht. / Es ist im Parlament, wo die Gesetze gemacht werden.","explanation":"\"Wo\" verwendet man nur für Orte: \"Es ist IM Parlament, WO...\"."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Es ist die Regierung, _____ die Verantwortung trägt. (die)', '["die","der","das","den"]', 'die', 'Regierung ist feminin -> Relativpronomen "die".', 1, 1),
  (l_id, 'multiple_choice', 'Was betont ein Cleft-Satz?', '["Das Verb","Ein bestimmtes Satzelement","Die Zeit","Die Modalität"]', 'Ein bestimmtes Satzelement', 'Cleft-Sätze betonen ein Satzelement (Subjekt, Objekt etc.).', 1, 2),
  (l_id, 'translation', 'Übersetze: "It is the voters who decide."', '["Es sind die Wähler, die entscheiden.","Es sind die Wähler, wer entscheidet.","Es ist die Wähler, die entscheiden.","Die Wähler sind es, wer entscheidet."]', 'Es sind die Wähler, die entscheiden.', 'Cleft-Satz: Es sind + Plural + Relativpronomen.', 1, 3),
  (l_id, 'fill_gap', 'Es ist der Bundestag, _____ die Gesetze verabschiedet. (der)', '["der","die","das","den"]', 'der', 'Bundestag ist maskulin -> Relativpronomen "der".', 1, 4),
  (l_id, 'multiple_choice', 'Welches Relativpronomen passt? "Es ist das Gesetz, _____ neu ist."', '["das","der","die","den"]', 'das', 'Gesetz ist Neutrum -> Relativpronomen "das".', 1, 5);
