  (l_id, 'der Vergleich', 'المقارنة', 'comparison', 'der', 'die Vergleiche', 'noun', 'Der Vergleich mit anderen EU-Ländern ist interessant.', 'The comparison with other EU countries is interesting.', 5);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Vergleiche mit als, als ob, als wenn', 'Irreale Vergleiche drücken aus, dass etwas so scheint, wie etwas anderes, aber nicht so ist. "Als" leitet einen irrealen Vergleichssatz ein (Konjunktiv II). "Als ob" und "als wenn" sind Alternativen (Nebensatz mit Verb am Ende). Die Bedeutung ist gleich, "als" ist formeller.', '[{"rule":"Irrealer Vergleich mit \"als\": als + Konjunktiv II (Verb direkt nach \"als\").","note":"Er tut so, als sei nichts passiert."},{"rule":"Irrealer Vergleich mit \"als ob\": als ob + Konjunktiv II (Verb am Ende).","note":"Er tut so, als ob nichts passiert sei."},{"rule":"Irrealer Vergleich mit \"als wenn\": als wenn + Konjunktiv II (Verb am Ende).","note":"Er tut so, als wenn nichts passiert wäre."},{"rule":"Im Vergleichssatz steht immer Konjunktiv II (Gegenwart/Vergangenheit).","note":"Sie sieht aus, als wäre sie krank. (Gegenwart irreales Vergangenheit)"},{"rule":"Der reale Vergleich verwendet \"wie\", der irreale \"als\".","note":"Real: Er ist groß, wie sein Vater. Irreal: Er tut so, als sei er der Chef."}]', '[{"german":"Die Politiker reden, als wüssten sie die Lösung.","arabic":"السياسيون يتحدثون كما لو أنهم يعرفون الحل.","english":"The politicians talk as if they knew the solution."},{"german":"Es sieht aus, als ob die Wirtschaft sich erholen würde.","arabic":"يبدو كما لو أن الاقتصاد يتعافى.","english":"It looks as if the economy were recovering."},{"german":"Die Regierung tut so, als wenn alles in Ordnung wäre.","arabic":"الحكومة تتصرف كما لو أن كل شيء على ما يرام.","english":"The government acts as if everything were in order."},{"german":"Der Minister sprach, als hätte er die Wahl bereits gewonnen.","arabic":"تكلم الوزير كما لو أنه فاز بالانتخابات بالفعل.","english":"The minister spoke as if he had already won the election."},{"german":"Es wirkt, als sei die Krise bereits überwunden.","arabic":"يبدو كما لو أن الأقدمة قد تم تجاوزها بالفعل.","english":"It seems as if the crisis has already been overcome."}]', '[{"mistake":"Er tut so, als ob er der Chef ist. (Indikativ statt Konjunktiv)","correction":"Er tut so, als ob er der Chef wäre.","explanation":"Im irrealen Vergleichssatz steht Konjunktiv II, nicht Indikativ."},{"mistake":"Sie sieht aus, als wie sie krank wäre.","correction":"Sie sieht aus, als wäre sie krank. / als ob sie krank wäre.","explanation":"Nicht \"als wie\" kombinieren. Entweder \"als\" oder \"als ob / als wenn\"."},{"mistake":"Er redet, als wenn er alles besser weiß. (Indikativ)","correction":"Er redet, als wenn er alles besser wüsste.","explanation":"Konjunktiv II nach \"als wenn\"."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Er tut so, _____ sei nichts passiert. (als)', '["als","als ob","als wenn","wie"]', 'als', '"Als" + Konjunktiv II (Verb direkt nach "als").', 1, 1),
  (l_id, 'multiple_choice', 'Welcher Satz ist ein irrealer Vergleich?', '["Er ist groß wie sein Vater.","Es sieht aus, als ob es regnen würde.","Die Sonne scheint.","Das Wetter ist schön."]', 'Es sieht aus, als ob es regnen würde.', 'Irrealer Vergleich mit "als ob" + Konjunktiv II.', 1, 2),
  (l_id, 'translation', 'Übersetze: "He acts as if he were the boss."', '["Er tut so, als wäre er der Chef.","Er tut so, als ist er der Chef.","Er tut so, wie er der Chef wäre.","Er tut so, als wenn er der Chef ist."]', 'Er tut so, als wäre er der Chef.', 'Irrealer Vergleich mit "als" + Konjunktiv II.', 1, 3),
  (l_id, 'fill_gap', 'Es sieht aus, als _____ die Wirtschaft sich erholen _____. (würde - als ob)', '["ob ... würde","ob ... wird","wenn ... würde","als ... würde"]', 'ob ... würde', '"Als ob" + Konjunktiv II (Verb am Ende).', 1, 4),
  (l_id, 'multiple_choice', 'Welches Signalwort leitet einen realen Vergleich ein?', '["als","wie","als ob","als wenn"]', 'wie', 'Realer Vergleich verwendet "wie": Er ist groß WIE sein Vater.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
  (l_id, 'multiple_choice', 'Was bedeutet "die Prognose"?', '["التوقعات","التطور","المقارنة","الاتجاه"]', 'التوقعات', 1, 1),
  (l_id, 'true_false', 'Nach "als" (irrealer Vergleich) kommt Konjunktiv II.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Er tut so, als _____ er der Chef. (sein - KII)', '["wäre","ist","sei","war"]', 'wäre', 1, 3),
  (l_id, 'multiple_choice', '"Als ob" und "als wenn" sind:', '["Synonyme","Gegenteile","Fragewörter","Präpositionen"]', 'Synonyme', 1, 4),
  (l_id, 'true_false', 'Nach "als ob" steht das Verb an Position 2.', '["Richtig","Falsch"]', 'Falsch', 1, 5),
  (l_id, 'multiple_choice', 'Welcher Satz ist ein realer Vergleich?', '["Er ist so groß wie sein Vater.","Er tut so, als wäre er groß.","Er sieht aus, als ob er groß wäre.","Als wäre er groß, redet er."]', 'Er ist so groß wie sein Vater.', 1, 6);
