  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Konjunktur', 'الدورة الاقتصادية', 'economic cycle', 'die', 'die Konjunkturen', 'noun', 'Die Konjunktur zeigt eine leichte Erholung.', 'The economy shows a slight recovery.', 1),
  (l_id, 'die Rezession', 'الركود', 'recession', 'die', 'die Rezessionen', 'noun', 'Die Wirtschaft befindet sich in einer Rezession.', 'The economy is in a recession.', 2),
  (l_id, 'der Aufschwung', 'الانتعاش', 'upswing', 'der', 'die Aufschwünge', 'noun', 'Der wirtschaftliche Aufschwung setzt sich fort.', 'The economic upswing continues.', 3),
  (l_id, 'die Arbeitslosenquote', 'معدل البطالة', 'unemployment rate', 'die', 'die Arbeitslosenquoten', 'noun', 'Die Arbeitslosenquote ist gesunken.', 'The unemployment rate has fallen.', 4),
  (l_id, 'der Export', 'التصدير', 'export', 'der', 'die Exporte', 'noun', 'Der Export ist eine wichtige Säule der deutschen Wirtschaft.', 'Exports are an important pillar of the German economy.', 5),
  (l_id, 'das Wachstum', 'النمو', 'growth', 'das', NULL, 'noun', 'Das Wirtschaftswachstum betrug 1,5 Prozent.', 'The economic growth was 1.5 percent.', 6);
  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Modalpartikeln, Cleft-Sätze und Vergleiche in Wirtschaftsnachrichten', 'In Wirtschaftsnachrichten kombinieren wir alle drei Grammatikthemen: Modalpartikeln (wohl für Vermutung, doch für Betonung), Cleft-Sätze (Es ist...der/die/das für Hervorhebung) und irreale Vergleiche (als ob/als für hypothetische Szenarien).', '[{"rule":"Modalpartikel \"wohl\" für Prognosen und Vermutungen.","note":"Die Wirtschaft wird sich wohl erholen."},{"rule":"Modalpartikel \"doch\" für Betonung von Fakten.","note":"Die Arbeitslosenquote ist doch gesunken."},{"rule":"Cleft-Satz für Hervorhebung des Subjekts.","note":"Es ist der Export, der das Wachstum antreibt."},{"rule":"Irrealer Vergleich für hypothetische Szenarien.","note":"Es sieht aus, als ob die Rezession vorbei wäre."}]', '[{"german":"Die Wirtschaft wird sich wohl im nächsten Jahr erholen.","arabic":"من المحتمل أن يتعافى الاقتصاد في العام القادم.","english":"The economy will probably recover next year."},{"german":"Es ist der Export, der das Wachstum antreibt.","arabic":"إن التصدير هو الذي يدفع النمو.","english":"It is exports that drive growth."},{"german":"Es sieht aus, als ob die Rezession überwunden wäre.","arabic":"يبدو كما لو أن الركود قد تم تجاوزه.","english":"It looks as if the recession had been overcome."},{"german":"Die Arbeitslosenquote ist doch gesunken, anders als erwartet.","arabic":"لقد انخفض معدل البطالة بالفعل، على عكس المتوقع.","english":"The unemployment rate has actually fallen, contrary to expectations."}]', '[{"mistake":"Die Wirtschaft wird wohl erholen. (fehlendes \"sich\")","correction":"Die Wirtschaft wird sich wohl erholen.","explanation":"\"Sich erholen\" ist ein reflexives Verb, \"sich\" darf nicht fehlen."},{"mistake":"Es ist der Export, was das Wachstum antreibt.","correction":"Es ist der Export, der das Wachstum antreibt.","explanation":"Export ist maskulin -> Relativpronomen \"der\", nicht \"was\"."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Die Wirtschaft wird sich _____ erholen. (Vermutung)', '["wohl","doch","halt","eigentlich"]', 'wohl', '"Wohl" drückt eine Vermutung aus.', 1, 1),
  (l_id, 'multiple_choice', 'Welcher Cleft-Satz ist korrekt?', '["Es ist der Export, der das Wachstum antreibt.","Es ist der Export, die das Wachstum antreibt.","Es ist der Export, das das Wachstum antreibt.","Es ist der Export, den das Wachstum antreibt."]', 'Es ist der Export, der das Wachstum antreibt.', 'Export maskulin -> Relativpronomen "der".', 1, 2),
  (l_id, 'translation', 'Übersetze: "It looks as if the recession were over."', '["Es sieht aus, als ob die Rezession vorbei wäre.","Es sieht aus, wie die Rezession vorbei ist.","Es sieht aus, als ob die Rezession vorbei ist.","Es sieht aus, als die Rezession vorbei wäre."]', 'Es sieht aus, als ob die Rezession vorbei wäre.', 'Irrealer Vergleich mit "als ob" + Konjunktiv II.', 1, 3),
  (l_id, 'fill_gap', 'Es ist der Export, _____ das Wachstum antreibt. (der)', '["der","die","das","den"]', 'der', 'Cleft-Satz: Es ist der Export, der ...', 1, 4),
  (l_id, 'multiple_choice', 'Was bedeutet "die Rezession"?', '["الركود","الانتعاش","النمو","التضخم"]', 'الركود', 'Rezession = economic downturn.', 1, 5);
