  (l_id, 'multiple_choice', 'Was bedeutet "die Arbeitslosenquote"?', '["معدل البطالة","معدل التضخم","النمو","التصدير"]', 'معدل البطالة', 1, 1),
  (l_id, 'true_false', '"Wohl" drückt eine Vermutung aus.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Es ist der Export, _____ (Relativpronomen) das Wachstum antreibt.', '["der","die","das","den"]', 'der', 1, 3),
  (l_id, 'multiple_choice', '"Als ob" leitet einen ... ein:', '["realen Vergleich","irrealen Vergleich","Kausalsatz","Temporalsatz"]', 'irrealen Vergleich', 1, 4),
