  insert into public.lesson_vocabulary (lesson_id, german_word, arabic_translation, english_translation, article, plural, part_of_speech, example_sentence, example_translation, order_index) values
  (l_id, 'die Globalisierung', 'العولمة', 'globalization', 'die', NULL, 'noun', 'Die Globalisierung hat die Weltwirtschaft verändert.', 'Globalization has changed the world economy.', 1),
  (l_id, 'der Freihandel', 'التجارة الحرة', 'free trade', 'der', NULL, 'noun', 'Der Freihandel fördert den wirtschaftlichen Austausch.', 'Free trade promotes economic exchange.', 2),
  (l_id, 'die Subvention', 'الدعم', 'subsidy', 'die', 'die Subventionen', 'noun', 'Die Subventionen für erneuerbare Energien wurden erhöht.', 'Subsidies for renewable energies were increased.', 3),
  (l_id, 'die Krise', 'الأزمة', 'crisis', 'die', 'die Krisen', 'noun', 'Die Finanzkrise hatte globale Auswirkungen.', 'The financial crisis had global effects.', 4),
