  insert into public.lesson_grammar (lesson_id, title, explanation, rules, examples, common_mistakes, order_index) values
  (l_id, 'Wiederholung: Modalpartikeln, Cleft-Sätze, irreale Vergleiche', 'In dieser Wiederholung festigen wir Modalpartikeln (doch, ja, eben, halt, eigentlich, wohl), Cleft-Sätze (Es ist...der/die/das für Hervorhebung) und irreale Vergleiche (als, als ob, als wenn mit Konjunktiv II).', '[{"rule":"Modalpartikeln: doch (Betonung), ja (bekannt), eben/halt (Resignation), eigentlich (eigentlich), wohl (Vermutung).","note":"Das ist doch klar. / Das ist ja bekannt."},{"rule":"Cleft-Sätze: Es ist + Nomen + Relativpronomen (der/die/das).","note":"Es ist die Regierung, die entscheidet."},{"rule":"Irreale Vergleiche: als/als ob/als wenn + Konjunktiv II.","note":"Er tut so, als wäre nichts passiert."},{"rule":"Realer Vergleich: wie. Irrealer Vergleich: als.","note":"Real: Er ist groß wie ich. Irreal: Er tut so, als sei er der Chef."}]', '[{"german":"Die Wirtschaft wird sich wohl erholen, aber es dauert eben.","arabic":"من المحتمل أن يتعافى الاقتصاد، لكنه يستغرق وقتاً ببساطة.","english":"The economy will probably recover, but it just takes time."},{"german":"Es ist die Zentralbank, die die Zinsen festlegt.","arabic":"إن البنك المركزي هو الذي يحدد أسعار الفائدة.","english":"It is the central bank that sets interest rates."},{"german":"Die Politiker reden, als ob sie die Lösung bereits hätten.","arabic":"السياسيون يتحدثون كما لو كان لديهم الحل بالفعل.","english":"The politicians talk as if they already had the solution."}]', '[{"mistake":"Das ist ja nicht interessant. (Modalpartikel + nicht)","correction":"Das ist nicht interessant. (ohne ja)","explanation":"Modalpartikeln können nicht mit \"nicht\" kombiniert werden."},{"mistake":"Es ist der Minister, wer die Entscheidung trifft.","correction":"Es ist der Minister, der die Entscheidung trifft.","explanation":"Relativpronomen \"der\", nicht \"wer\"."},{"mistake":"Er tut so, als ob er der Chef ist.","correction":"Er tut so, als ob er der Chef wäre.","explanation":"Im irrealen Vergleich steht Konjunktiv II (wäre), nicht Indikativ (ist)."}]', 1);
  insert into public.lesson_exercises (lesson_id, exercise_type, question, options, correct_answer, explanation, points, order_index) values
  (l_id, 'fill_gap', 'Die Wirtschaft wird sich _____ erholen. (Vermutung - wohl/doch)', '["wohl","doch","halt","eigentlich"]', 'wohl', '"Wohl" drückt eine wahrscheinliche Vermutung aus.', 1, 1),
  (l_id, 'multiple_choice', 'Welcher Satz ist ein Cleft-Satz?', '["Es ist die Regierung, die entscheidet.","Die Regierung entscheidet.","Die Regierung wird entscheiden.","Die Regierung hat entschieden."]', 'Es ist die Regierung, die entscheidet.', 'Cleft-Satz: Es ist + Nomen + Relativpronomen.', 1, 2),
  (l_id, 'translation', 'Übersetze: "He talks as if he were the expert."', '["Er redet, als ob er der Experte wäre.","Er redet, wie der Experte.","Er redet, als ob er der Experte ist.","Er redet, als er der Experte wäre."]', 'Er redet, als ob er der Experte wäre.', 'Irrealer Vergleich mit "als ob" + Konjunktiv II.', 1, 3),
  (l_id, 'fill_gap', 'Es ist die Zentralbank, _____ die Zinsen festlegt. (die)', '["die","der","das","den"]', 'die', 'Zentralbank feminin -> Relativpronomen "die".', 1, 4),
  (l_id, 'multiple_choice', 'Welche Modalpartikel drückt Resignation aus?', '["doch","ja","eben","wohl"]', 'eben', '"Eben" (= halt) drückt Resignation oder Unvermeidlichkeit aus.', 1, 5);
  insert into public.lesson_test_questions (lesson_id, question_type, question, options, correct_answer, points, order_index) values
