  (l_id, 'true_false', 'Modalpartikeln können den Satzton verändern.', '["Richtig","Falsch"]', 'Richtig', 1, 2),
  (l_id, 'fill_blank', 'Es ist der Export, _____ (Relativpronomen) das Wachstum antreibt.', '["der","die","das","den"]', 'der', 1, 3),
  (l_id, 'multiple_choice', '"Als ob" + Konjunktiv II drückt aus:', '["einen realen Vergleich","einen irrealen Vergleich","einen Kausalsatz","einen Temporalsatz"]', 'einen irrealen Vergleich', 1, 4),
  (l_id, 'true_false', '"Eigentlich" drückt eine Vermutung aus.', '["Richtig","Falsch"]', 'Falsch', 1, 5),
  (l_id, 'multiple_choice', 'Welche Partikel passt? "Das ist _____ so, leider." (Resignation)', '["halt","doch","wohl","eigentlich"]', 'halt', 1, 6),
  (l_id, 'fill_blank', 'Er tut so, _____ ob er der Chef wäre. (als)', '["als","wie","denn","weil"]', 'als', 1, 7),
  (l_id, 'multiple_choice', 'Was bedeutet "die Sanktionen"?', '["العقوبات","الدعم","الاستثمار","الضرائب"]', 'العقوبات', 1, 8);
